INSERT INTO `buildings` (`id`, `desc`, `energy`, `warehouse`, `map_char`, `req_id`, `native`, `shield`, `atack`, `w_type`) VALUES
(23, 'Позволяет добывать ресурсы с поверхности планеты. Количество циклов зависит от уровня развития данной структуры. Для постоянной добычи можно использовать автономных роботов.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-10</font><br>	Склад					<font color="#00FF00">1000</font>', -10, 1000, 'K', 24, 1, 0, 0, 0),
(24, 'Переплавляет ископаемые, и ненужные устройства в ресурсы. Качество переплавки зависит от уровня структуры.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-15</font><br>	Склад					<font color="#00FF00">1000</font>', -15, 1000, 'P', 34, 1, 0, 0, 0),
(25, 'Позволяет исследовать агрегаты, устройства, чертежи, продуктом деятельности является чертеж агрегата необходимый для изготовления. Уровень постройки определяет время исследования.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-35</font><br>	Склад					<font color="#00FF00">500</font>', -35, 500, 'L', 39, 1, 0, 0, 0),
(26, 'Изначальная структура в которой вы спустились на планету. Обладает возможностью полностью регенирировать игрока и восстанавливать память.<br><br><b>Свойства</b><br>	Энергии				<font color="#00FF00">50</font><br>	Склад					<font color="#00FF00">5000</font>', 50, 5000, 'C', NULL, 1, 0, 0, 0),
(33, 'Позволяет изготавливать вещи при наличии чертежа и ресурсов. Количество циклов производства зависит от уровня структуры. Для постоянной работы можно воспользоваться автономными роботами.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-50</font><br>	Склад					<font color="#00FF00">5000</font>', -50, 5000, 'F', 24, 1, 0, 0, 0),
(34, 'Вырабатывает электроэнергию необходимую всем постройкам на планете, без энергии не функционирует ни одна постройка. Количество вырабатываемой энергии зависит от уровня постройки.<br><br><b>Свойства</b><br>	Энергии				', 100, 0, 'E', NULL, 1, 0, 0, 0),
(36, 'Позволяет добывать ресурсы с среднего слоя планеты. Перед постройкой желательно исследовать пространство с помощью зонда или геологического спутника.  Количество циклов зависит от уровня развития данной структуры. Для постоянной добычи можно использовать автономных роботов.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-30</font><br>	Склад					<font color="#00FF00">1000</font>', -30, 1000, 'M', 24, 1, 0, 0, 0),
(37, 'Позволяет добывать ресурсы с глубинного слоя планеты.  Перед постройкой желательно исследовать пространство с помощью зонда или геологического спутника. Количество циклов зависит от уровня развития данной структуры. Для постоянной добычи можно использовать автономных роботов.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-60</font><br>	Склад					<font color="#00FF00">1000</font>', -60, 1000, 'O', 24, 1, 0, 0, 0),
(38, 'Позволяет хранить больше товара на планете. Количество хранимых товаров зависит от уровня постройки.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-10</font><br>	Склад					', -10, 250000, 'S', 24, 1, 0, 0, 0),
(39, 'Позволяет изготавливать сложные устройства, собираемые из нескольких модулей.', -70, 5000, 'R', 33, 1, 0, 0, 0),
(2000, 'Исследовать почву', 0, 0, '0', 33, 1, 0, 0, 0),
(3001, 'Торговая станция является собственностью земной федерации, позволяет выставлять на продажу товары игрока, а так же запрашивать закупку товаров. Станция обеспечивает неприкосновенность изначальной планеты.<br><br><b>Свойства</b><br>	Энергии				<font color="#00FF00">300</font><br>	Склад					<font color="#00FF00">50000</font>', 300, 50000, 'T', NULL, 1, 0, 0, 0),
(3002, 'Позволяет исследовать полностью поверхность планеты :<br>5-ый уровень весь средний слой<br>10-ый уровень весь глубинный слой<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-500</font>', -500, 0, 'G', NULL, 1, 0, 0, 0),
(3003, 'Добывает колосальное количество энергии преобразуя свободную солнечную энергию электричество. Из за отсутсвия гравитации солнечные панели распространяются на несколько километров вокруг спутника.<br><br><b>Свойства</b><br>	Энергии				', 1000, 0, 'A', NULL, 1, 0, 0, 0),
(3004, 'Позволяет хранить на орбите ресурсы.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-800</font><br>	Склад					', -800, 120000, 'I', 3003, 1, 0, 0, 0),
(3005, 'Позволяет собирать большие корабли которые из-за своего веса не могут приземлится на поверхность планеты.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-2000</font>', -2000, 2000, 'Q', 3003, 1, 0, 0, 0),
(3006, 'Позволяет добывать газ из верхних слоев атмосферы некоторых планет. Используется на орбите газовых гигантов. Требует для постройки наличие электростанции<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-250</font>', -250, 3000, 'W', 3003, 1, 0, 0, 0),
(27, 'Защищает планету используя ракеты земля-воздух. Количество выстрелов за один залп зависит от уровня постройки.<br><br><b>Свойства</b><br>	Сила выстрела				2<br>	Количество					', 0, 0, 'D', NULL, 0, 0, 2, 3),
(28, 'Защищает планету используя лазер наземного базирования. Лазер наносит множество малых по силе ударов, выводя из строя множество малых кораблей.<br><br><b>Свойства</b><br>', 0, 0, 'H', NULL, 0, 0, 50, 0),
(29, 'Защищает планету используя перегретую плазму. Плазма наносит редкие, но сильные удары, выводя из строя крупные корабли.<br><br><b>Свойства</b><br>', 0, 0, 'J', NULL, 0, 0, 75, 1),
(30, 'Защищает планету используя микроволновое излучение. Генератор наносит удар на все корабли находящиеся в атмосфере, что делает его эффективным против большого количества слабых кораблей.<br><br><b>Свойства</b><br>', 0, 0, 'N', NULL, 0, 0, 1, 2),
(31, 'Защищает планету не нанося урона врагу блокирует все виды оружия при этом позволяя атаковать нападающих. Количество поглащенной энергии зависит от уровня постройки. В случае нападения щит уничтожается в первую очередь.<br><br><b>Свойства</b><br>	Щит				', 0, 0, 'U', NULL, 0, 1000, 0, 0),
(3007, 'Защищает планету используя лазерное оружие.<br><br>', 0, 0, 'V', NULL, 0, 500, 50, 0),
(3008, 'Защищает планету используя плазменное оружие.<br><br><b>Свойства</b><br>', 0, 0, 'X', NULL, 0, 500, 25, 1),
(3009, 'Защищает планету используя квантовый генератор. Поражая все цели одновременно<br><br><b>Свойства</b><br>', 0, 0, 'Y', NULL, 0, 300, 1, 2),
(3010, 'Позволяет превращать одно вещество в другое используя энергию получаемую во время самого преобразования.<br><br><b>Свойства</b><br>	Энергии				<font color="#FF0000">-2500</font><br>	Склад					<font color="#00FF00">100000</font>', -2500, 100000, 'Z', 3004, 1, 0, 0, 0);
