INSERT INTO `quest_types` (`type`, `name`, `desc`, `status`, `cnt`, `arg0`, `arg1`, `arg2`, `arg3`, `arg4`, `arg5`, `arg6`, `arg7`, `arg8`, `arg9`) VALUES
(1, 'Для постройки корабля требуется %arg5 в количестве %arg1. Награда %arg3 кредитов.', 'Конфедерация нашла макет неизвестного корабля и для испытания надо построить этот корабль, ваша помощь может оказаться очень кстати, требуется %arg5 в количестве %arg1. Конфедерация готова заплатить %arg3 кредитов тому, кто поможет с добычей. Конфедерация позаботится и доставит его самостоятельно с вашей родной планеты. Конфедерация всегда помнит о тех, кто оказывает помощь, ваш уровень ответственности изменится соответственно.', 2, 3, 'null', '(round(rand()*40)+10)*100', '%seed%%49+1000', 'round(arg1 / 10)', 'round(arg1 / 100)', '(SELECT name FROM objects WHERE id = %seed%%49+1000)', 'null', 'null', 'null', 'null'),
(2, 'Найти потерянный корабль в системе %arg4. Награда %arg2 кредитов.', 'Не так давно из системы %arg4 поступил сигнал экстренной помощи, сигнал был очень слабым и точные координаты корабля установить не удалось. Если вы готовы помочь, вам будет необходим радарный корабль и транспортный корабль с топливом. Нужно переместится в систему %arg4, отыскать корабль и объединится с кораблем в флот. От вас требуется доставить корабль до ближайшей планеты где есть станция конфедерации и состыковаться со станцией. В качестве вознаграждения вы получите %arg2 кредитов и благодарность от спасенных людей. Конфедерация всегда помнит о тех, кто оказывает помощь, ваш уровень ответственности изменится соответственно.', 6, 5, 'null', '(SELECT star_id FROM planets WHERE user_id IS NOT NULL ORDER BY rand(%seed%) LIMIT 0,1)', 'round(rand()*40+10)*100', 'round(arg2/10)', '(SELECT s.name FROM planets p INNER JOIN stars s ON s.id = p.star_id WHERE p.user_id IS NOT NULL ORDER BY rand(%seed%) LIMIT 0,1)', 'null', 'null', 'null', 'null', 'null'),
(3, 'Перевезти пакет из системы %arg1 в систему %arg3. Награда %arg4 кредитов', 'Некоторые сведения нельзя доверять гиперпередаче и требуется доброволец для доставки секретных сведений. Пакет содержит цифровой монокристалл который практически не поддается расшифровке. Вам необходимо пристыковаться к торговой станции в звездной системе %arg1 после проверки вашего корабля вам лично в руки будет передан пакет. Ваша задача как можно быстрее добраться до системы %arg3 и пристыковаться к торговой станции. Награда %arg4 кредитов. Вам необходимо ЛИЧНО присутствовать на корабле.', 5, 3, '(SELECT star_id FROM planets WHERE user_id IS NOT NULL ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT s.name FROM planets p INNER JOIN stars s ON s.id = p.star_id WHERE p.user_id IS NOT NULL ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT star_id FROM planets WHERE user_id IS NOT NULL ORDER BY rand(%seed%+13) LIMIT 0,1)', '(SELECT s.name FROM planets p INNER JOIN stars s ON s.id = p.star_id WHERE p.user_id IS NOT NULL ORDER BY rand(%seed%+13) LIMIT 0,1)', 'round(rand()*50+50)*100', 'round(arg4/100)', 'null', 'null', '(SELECT star_id FROM planets WHERE user_id IS NOT NULL ORDER BY rand(%seed%+25) LIMIT 0,1)', '(SELECT s.name FROM planets p INNER JOIN stars s ON s.id = p.star_id WHERE p.user_id IS NOT NULL ORDER BY rand(%seed%+25) LIMIT 0,1)'),
(4, 'Уничтожить %arg2 Трититов в системе %arg1. Награда %arg3 кредитов', 'В системе %arg1 активизировались Трититы, силы конфедерации далеко от звезды и поэтому требуется ваша помощь. Необходимо собрать флот и отправится в систему %arg1, нам необходимо быть уверенными в положительном исходе войны. По данным разведки в системе %arg1 обнаружено %arg2 Трититов, но конфедерация не располагает точными сведениями о боевой мощи этого флота.', 4, 3, '(SELECT id FROM stars ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT name FROM stars ORDER BY rand(%seed%) LIMIT 0,1)', 'round(rand()*17+3)', 'round(arg2*100)', 'null', 'null', 'null', 'null', 'null', 'null'),
(5, 'Для торговой станции требуется %arg5 в количестве %arg1. Награда %arg3 кредитов.', 'Конфедерация исследуя новые рубежи галактики постоянно занята строительством торговых станций однако случаются нападения пиратов и Трититов на транспортные корабли, от чего часть ресурсов теряется. Для завершения постройки торговой станции требуется %arg5 в количестве %arg1. Конфедерация готова заплатить %arg3 кредитов тому, кто поможет с добычей. Конфедерация позаботится и доставит его самостоятельно с вашей родной планеты. Конфедерация всегда помнит о тех, кто оказывает помощь, ваш уровень ответственности изменится соответственно.', 2, 3, 'null', '(round(rand()*40)+10)*100', '%seed%%49+1000', 'round(arg1 / 10)', 'round(arg1 / 100)', '(SELECT name FROM objects WHERE id = %seed%%49+1000)', 'null', 'null', 'null', 'null'),
(6, 'Добыть %arg5 в количестве %arg1. Награда %arg3 кредитов.', 'Конфедерации планет требуется ваша помощь. В настоящий момент все производственные мощности работают в полную силу, однако требуется еще %arg5 в количестве %arg1. Конфедерация готова заплатить %arg3 кредитов тому, кто поможет с добычей. Конфедерация позаботится и доставит его самостоятельно с вашей родной планеты. Конфедерация всегда помнит о тех, кто оказывает помощь, ваш уровень ответственности изменится соответственно.', 2, 3, 'null', '(round(rand()*40)+10)*100', '%seed%%49+1000', 'round(arg1 / 10)', 'round(arg1 / 100)', '(SELECT name FROM objects WHERE id = %seed%%49+1000)', 'null', 'null', 'null', 'null'),
(7, 'Требуется минерал %arg5 в количестве %arg1. Награда %arg3 кредитов.', 'Для экспериментов на глюоном ускорителе требуется чистый минерал %arg5 в количестве %arg1. От результатов эксперимента зависит будущее науки. Конфедерация готова заплатить %arg3 кредитов тому, кто поможет с добычей. Конфедерация позаботится и доставит его самостоятельно с вашей родной планеты. Конфедерация всегда помнит о тех, кто оказывает помощь, ваш уровень ответственности изменится соответственно.', 2, 1, 'null', '(round(rand()*10)+10)*100', '(SELECT id FROM objects WHERE class = 5 ORDER BY rand(%seed%) LIMIT 1,1)', 'round(arg1 / 2)', 'round(arg1 / 100)', '(SELECT name FROM objects WHERE class = 5 ORDER BY rand(%seed%) LIMIT 1,1)', 'null', 'null', 'null', 'null'),
(8, 'Предотвратите вторжение армии Трититов в системе %arg1. Награда %arg3 кредитов', 'В системе %arg1 обнаружено сильное искажение пространства Трититы объединились в армию и начали уничтожение всего живого, силы конфедерации далеко от звезды и поэтому требуется ваша помощь. Необходимо собрать сильный флот и отправится в систему %arg1, нам необходимо быть уверенными в положительном исходе войны. По данным разведки в системе %arg1 обнаружено не менее %arg2 Трититов, но конфедерация не располагает точными сведениями о боевой мощи этого флота.', 4, 3, '(SELECT id FROM stars WHERE type != 4 ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT name FROM stars WHERE type != 4 ORDER BY rand(%seed%) LIMIT 0,1)', 'round(rand()*50+20)', 'round(arg2*100)', 'null', 'null', 'null', 'null', 'null', 'null'),
(9, 'Освободите оккупированную планету %arg3 в системе %arg1 вознаграждение %arg5 кредитов', 'В системе %arg1 пираты оккупировали и удерживают под своим контролем планету %arg1 Конфедерация не вмешивается во внутренние конфликты, однако готова выплатить %arg5 кредитов за вашу помощь в освобождении планеты. По данным предварительной разведки на орбите находится %arg4 кораблей. Будьте предусмотрительны, пираты могут не дать вам второго шанса.', 4, 3, '(SELECT s.id FROM planets p LEFT JOIN orbits_buildings ob ON ob.planet_id = p.id LEFT JOIN stars s ON s.type != 4 AND p.star_id = s.id WHERE p.user_id IS NULL AND ob.id IS NULL ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT s.name FROM planets p LEFT JOIN orbits_buildings ob ON ob.planet_id = p.id LEFT JOIN stars s ON s.type != 4 AND p.star_id = s.id WHERE p.type IN( 2, 3, 4 ) AND ob.id IS NULL ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT p.id FROM planets p LEFT JOIN orbits_buildings ob ON ob.planet_id = p.id LEFT JOIN stars s ON s.type != 4 AND p.star_id = s.id WHERE p.type IN( 2, 3, 4 ) AND ob.id IS NULL ORDER BY rand(%seed%) LIMIT 0,1)', '(SELECT p.name FROM planets p LEFT JOIN orbits_buildings ob ON ob.planet_id = p.id LEFT JOIN stars s ON s.type != 4 AND p.star_id = s.id WHERE p.type IN( 2, 3, 4 ) AND ob.id IS NULL ORDER BY rand(%seed%) LIMIT 0,1)', 'round(rand()*35+35)', 'round(arg4*100)', 'null', 'null', 'null', 'null'),
(12, 'Исследовать неизвестную точку в пространстве. Координаты %arg2 x %arg3. Награда %arg0', 'Автоматические разведчики конфедерации заметили странное искажение в пространстве. Вам предоставляется честь исследовать точку в пространстве. Помните, что завершение этой миссии в любом случае необходимо для конфедерации. Точка в пространстве с координатами %arg2:%arg3 излучает слишком много энергии, а плотность вещества в этой точке значительно превышает плотность космического вакуума. От этого задания нельзя будет отказаться, в случае неудачи вам придется воспользоваться помощью других пилотов. Награда %arg0', 2, 1, 'round(rand()*25000) + 5000', 'round(rand()*6)', 'round(sin(rand(%seed%)*7)*(rand(%seed%+10)*100+700))', 'round(cos(rand(%seed%)*7)*(rand(%seed%+10)*100+700))', 'null', 'null', 'null', 'null', 'null', 'null'),
(13, 'Переломить ход между пиратами и конфедерацией. В точке пространства %arg2 x %arg3. Награда %arg0', 'Корабли конфедерации, во время патрулирования, обнаружили флот пиратов. Силы двух противостоящих флотов практически равны. Обе стороны не решаются начать бой зная, что в живых не останется никто. У вас есть возможность встать на сторону конфедерации или пиратов и переломить ход этой битвы! Торопитесь, противник тоже собирает подмогу и битва вот-вот начнется. Координаты столкновения %arg2:%arg3 это точка в гиперпространстве. Как поступить с союзниками противника решать вам. Главное это исход назначенного сражения. Конфедерация предлагает вам награду в %arg0 кредитов за то, что вы встанете на их сторону. Учтите, до окончания битвы нельзя будет отказаться от этого задания. Вам придется дождаться конца сражения.', 3, 1, 'round(rand()*2500) + 5000', 'null', 'round(sin(rand(%seed%)*7)*(rand(%seed%+10)*100+700))', 'round(cos(rand(%seed%)*7)*(rand(%seed%+10)*100+700))', 'null', 'null', 'null', 'null', 'null', 'null'),
(14, 'Переломить ход между пиратами и конфедерацией. В точке пространства %arg2 x %arg3. Награда %arg0', 'В гиперпространстве столкнулись флота конфедерации и пиратов. К ним уже примкнуло подкрепление! У вас есть шанс внести свой вклад в эту битву. Чем быстрее вы отправитесь на эту битву, тем больше у вас шансов. У вас есть возможность встать на сторону конфедерации или пиратов и переломить ход этой битвы! Координаты столкновения %arg2:%arg3 это точка в гиперпространстве. Как поступить с союзниками противника решать вам. Главное это исход назначенного сражения. Конфедерация предлагает вам награду в %arg0 кредитов за то, что вы встанете на их сторону. Учтите, до окончания битвы нельзя будет отказаться от этого задания. Вам придется дождаться конца сражения.', 3, 0, 'null', 'null', 'null', 'null', 'null', 'null', 'null', 'null', 'null', 'null');
INSERT INTO `tutorials` (`level`, `page_id`, `premium`, `tutorial`) VALUES
(1, 1, 0, '1(34) Добро пожаловать!\n\nВы прошли обучение в "Академии дальней разведки" и теперь получили возможность колонизировать планету. В качестве отправной точки была найдена звездная система с планетой земного типа. Конфедерация планет гарантирует вам полную безопасность на этой планете. Однако никто не ограничивает вас в действиях, и вы имеете полное право колонизировать любые другие планеты. Конфедерация осуждает взаимное нападение, однако не вмешивается в боевые действия, за исключением случаев, когда объект находится под охраной конфедерации.\n\nНа начальном этапе вас будут сопровождать обучающие сообщения, от точного выполнения заданий зависит время, за которое вы адаптируетесь к новым условиям чужой планеты. По окончании обучения конфедерация выплатит вам 10 конфедерат.'),
(2, 1, 0, '2(34) Вы находитесь в модуле управления обучением.\n\nК сожалению, дальний перелет невозможен без криокамеры, а это накладывает отпечаток на память. Все приобретенные знания забываются, однако благодаря технологии регенерации нейросетей есть возможность восстановить эти знания. Вам следует определить только последовательность восстановления знаний.\n\nКаждое знание, умение или навык дает новые возможности. Некоторые из них необходимы для производства или осуществления управления. Другие лишь ускоряют процессы. Чем выше уровень, тем труднее восстанавливать нейронные связи, поскольку восстановление общей картины ведется наведенными токами большой мощности. В то же время для восстановления деталей необходимы токи малой мощности, что увеличивает время обучения.\nОбучение нельзя прервать, поскольку часть мозга окажется заблокированной навсегда. Знания, полученные при обучении сразу отпечатываются в матрице регенерационной машины, что позволит в последующем восстанавливать тело и память одновременно.'),
(3, 2, 0, '3(34) Вы находитесь в модуле управления окружающим пространством.\n\nВ настоящий момент вы находитесь на планете, на экране вы можете видеть поверхность планеты. В левом верхнем углу есть иконка "мини карты" если подвести к ней указатель раскроется карта, кликнув в любой точке на карте, вы быстро переместитесь в нужное место. Все постройки на карте отображаются яркой белой точкой, в то время как поверхность отображается соответствующим цветом.\nПервая постройка, которая есть на вашей планете это "капсула". Капсула представляет собой космический корабль, на котором вы прибыли на планету. Корабль снабжен устройством регенерации, что позволяет вам полностью восстанавливать тело и память после гибели. \nНа корабле есть минимальный запас минералов, который позволит вам начать развитие. Отнеситесь ответственно к первым шагам на планете, если вы неправильно распределите изначальные ресурсы вы, не сможете правильно начать развивать свою колонию.\n\nНа экране слева вы видите панель управления, состоящую из 3-х основных частей.\n<b>Информация</b> - в данной закладке отображается информация о точке на планете, а так же основные сведения о постройках. Из этой закладки в случае необходимости можно осуществить снос любого сооружения кроме капсулы.\n<b>Использование</b> - в данной закладке отображаются все возможные действия с выделенным объектом. Из этой закладки осуществляется строительство, запуск шахт карьеров, заводов и пр. Если постройка не несет в себе созидательной функции, в данной закладке отображаются все хранимые вещи.\n<b>Усовершенствовать</b> - в данной закладке отображаются возможность по усовершенствованию построек. Так же из этой закладки можно запустить исследования почвы (Необходим геологический зонд) что позволит добывать более редкие минералы.\n'),
(4, 2, 500, '4(34) Электростанция.\n\nДля начала необходимо построить Электростанцию, это обеспечит вас энергией.\nВыберите свободное место на планете и перейдите в панель "Использовать".\nУстановите тип постройки "Электростанция" и начните строительство нажатием кнопки "Начать строительство".\n\nНа карте появится пустая платформа и таймер красного цвета. Цвет таймера зависит от события, стройка отображается красным цветом. Когда строительство будет завершено, на карте появится здание электростанции. Поскольку электростанция не несет в себе дополнительных функций, в закладке "использование" можно увидеть какие вещи присутствуют на планете, а так же количество доступной энергии.\n\n<i>Постройте электростанцию</i>\n<b>вознаграждение: 500</b>'),
(5, 2, 500, '5(34) Нанодиспенсер\n\nТеперь, когда у вас есть электростанция, вы можете построить "Нанодиспенсер". Нанодиспенсер - позволяет перерабатывать сложные вещества или детали, разбирая их на атомарном уровне. В результате получаются чистые материалы. Существует минимально-необходимое количество материала для начала процесса, однако максимальное количество никак не ограничено. Время, которое затрачивается на выделение материалов, не зависит от количества сырья.\nДля постройки выберете любую свободную поверхность, зайдите в панели слева в закладку "Использовать" и выберите "Нанодиспенсер", начните строительство.\n\n<i>Постройте нанодиспенсер</i>\n<b>вознаграждение: 500</b>'),
(7, 6, 0, '7(34) Железо\n\nТеперь необходимо найти минерал содержащий Железо.\nДля этого выберите слева "Железо" и, заходя в каждый минерал из описания справа, найдите минерал первой группы.\n\n<i>Найдите минерал 1-го слоя содержащий железо</i>\n'),
(8, 6, 0, '8(34) Гематит\n\nГематит - как видно из описания это полезное ископаемое первой группы, соответственно добывать его можно используя карьер. Теперь можно вернуться на страницу "Местность" и начать разработку этого полезного ископаемого.'),
(9, 2, 500, '9(34) Гематит\n\nДля начала разработки Гематита необходимо обнаружить его на планете, для этого на панели слева необходимо выбрать вкладку "Информация" и переходя по разным областям на планете найти область с Гематитом. Визуально поверхность представляет собой травянистую поляну.\n\nКак правило во время посадки капсула производит предварительную разведку поверхности и старается приземлится в центральной зоне гематита.\n\n<i>Найдите на поверхности Гематит</i>\n\n<b>вознаграждение: 500</b>'),
(10, 2, 500, '10(34) Карьер\n\nГематит найден, можно приступать к его разработке.\nДля этого выберите в панели слева закладку "Использовать". В списке построек нам необходим "карьер". Постройте карьер в той точке, где был найден гематит.\n\n<i>Постройте карьер для добычи Гематита</i>\n\n<b>вознаграждение: 500</b>'),
(6, 2, 0, '6(34) Энциклопедия\n\nПосле постройки нанодиспенсера можно начать разработку полезных ископаемых. Прежде всего, необходимо наладить добычу железа и кремния, так как это основные компоненты строительства. Для этого, нужно узнать в какой породе содержится достаточное количество этих минералов.\nТочные справочные сведения содержатся в Энциклопедии в закладке "прочее".\n\n<i>Перейдите в прочее, выберите энциклопедию</i>\n'),
(11, 2, 1000, '11(34) Кремний\n\nТеперь необходимо позаботится о втором по необходимости материале - кремнии. Для этого в Энциклопедии нам необходимо найти кремний, а затем выбрать из полезных ископаемых ископаемое первого уровня, что бы можно было легко обнаружить его на поверхности.\n\n<i>Найдите полезное ископаемое первой группы в составе которого присутствует Кремний</i>\n\n<b>вознаграждение: 1000</b>'),
(12, 6, 0, '12(34) Кварц.\n\nВы правильно нашли полезное ископаемое, которое необходимо. Как вы видите "кварц" находится на первом уровне, а соответственно его будет легко найти на планете. Внешне это ископаемое выглядит как желтый песок.'),
(13, 2, 500, '13(34) Карьер\n\nКварц найден. Запомните как он выглядит, это позволит в будущем наращивать производственные мощности.\nТеперь необходимо начать его разработку, для этого в левой панели необходимо выбрать "Использовать", а затем тип постройки "Карьер" и запустить строительство.\n\n<i>Постройте карьер для добычи кварца</i>\n\n<b>вознаграждение: 500</b>'),
(14, 2, 1000, '14(34) Запуск производства\n\nТеперь необходимо запустить карьеры. Для этого необходимо выделить карьер на карте, в левой панели перейти в закладку "Использовать" и запустить цикл.\nКоличество доступных циклов зависит от уровня карьера. Чем выше уровень карьера, тем больше циклов без перезапуска доступно. Для безостановочной добычи используйте роботов, это позволит добывать больше ресурсов не теряя времени на простой производства.\nВ независимости от количества запущенных циклов любой процесс производства можно прервать. Для увеличения уровня постройки необходимо выбрать пункт меню "Усовершенствовать" и запустить усовершенствование.\nКоличество добытых ископаемых можно посмотреть в нейтральных постройках, таких как Капсула, Электростанция или Склад. Вам необходимо добыть 100 единиц полезных ископаемых.\n\n<i>Запустите карьеры для добычи кварца и гематита необходимо добыть 100 кварца и 100 гематита</i>\n\n<b>вознаграждение: 1000</b>\n'),
(15, 2, 1500, '15(34) Переработка\n\nКоличество добытых полезных ископаемых достигло уровня переработки. Теперь можно загрузить их в нанодиспенсер и переработать, что бы получить чистые минералы. Для этого выделите нанодиспенсер, а в левой панели выберите закладку "Использовать". В выпадающем списке будут все детали и полезные ископаемые, которые можно переработать.\nЧем выше уровень постройки, тем выше КПД, соответственно тем больше материалов получится из того же количества сырья. На первом уровне КПД 70%25\n\n<i>Переработайте полезные ископаемые в нанодиспенсере и получите элементы</i>\n\n<b>вознаграждение: 1500</b>\n'),
(16, 2, 2000, '16(34) Титан\n\nТеперь вам предоставляется возможность самостоятельно найти и разработать новый материал. <b>Титан</b>. Он понадобится для производства геологических зондов.\n\nТитан является распространенным материалом, однако до изобретения наноботов его было очень трудно перерабатывать из-за его высокой температуры плавления и большой прочности. В настоящее время Титан используется повсеместно, раньше эту нишу производства занимал алюминий и его сплавы с магнием.\n\n<i>Найдите в энциклопедии полезное ископаемое первой группы в состав которого входит титан, установите карьер, добудьте и переработайте полученные полезные ископаемые, что бы получить титан.</i>\n\n<b>вознаграждение: 2000</b>\n'),
(17, 2, 1000, '17(34) Завод\n\nВы самостоятельно нашли, добыли и переработали полезные ископаемые и получили Титан. Теперь необходимо начать производство. Для этого найдите пустое место на поверхности и постройте "Завод".\n\n<i>Постройте завод на пустой точке поверхности</i>\n\n<b>вознаграждение: 1000</b>'),
(18, 2, 2000, '18(34) Геологический зонд.\n\nДля работы заводу необходимы как полезные ископаемые, так и чертежи, чертеж представляет собой программу, в которой подробнейшим образом расписано в какой последовательности и как именно сгруппированы атомы в конечном продукте. Для оптимизации размера такие программы применяют фрактальные вычисления.\nВыберите "завод" на поверхности, на панели слева зайдите в закладку "Использовать" и в выпадающем списке выберите "Геологический зонд".\nВ таблице отмечены материалы, которые необходимы для постройки зонда.\nМатериалы, которых не хватает, отмечены красным. Необходимо добыть и переработать еще полезных ископаемых, что бы получить необходимое количество материалов.\nЕсли все необходимое присутствует на складе, можно запускать производство. Количество последовательно произведенных устройств зависит от уровня завода, чем выше уровень завода, тем большее количество устройств может быть произведено без вашего вмешательства. Для обеспечения безостановочного производства следует использовать роботов.\n\n<i>Изготовьте геологический зонд</i>\n\n<b>вознаграждение: 2000</b>\n'),
(19, 2, 3000, '19(34) Геологоразведка.\n\nГеологический зонд необходим для исследования поверхности.\nВыберите свободное место на поверхности, в левой панели перейдите в закладку "усовершенствовать" и запустите исследование поверхности. После запуска зонда исследуется следующий неисследованный слой.\nМатериалы верхнего слоя расположены пластами и легко определяются визуально, материалы среднего и глубинного слоя расположены точечно и их расположение совершенно случайно.\nДля добычи материалов среднего слоя необходимо использовать шахту. Для добычи материалов глубинного слоя необходимо использовать буровую. На одной единице поверхности может располагаться только одна постройка.\n\n<i>Исследуйте средний или глубинный слой</i>\n\n<b>вознаграждение: 3000</b>\n'),
(20, 2, 2000, '20(34) Сборочный цех\n\nВы прошли вводный курс, теперь вам предоставляется самостоятельно разработать и построить космический челнок. У вас в капсуле есть все необходимые чертежи и макеты. Используйте роботов на добывающих предприятиях, это сэкономит время и позволит накопить ресурсы.\nДля сборки челнока вам понадобится "Сборочный цех" постройте его на любой свободной поверхности.\n\n<i>Постройте сборочный цех.</i>\n\n<b>вознаграждение: 2000</b>'),
(21, 2, 0, '21(34) Корабли\n\nТеперь можно запустить все добывающие предприятия, для большей производительности используйте роботов, это позволит вам отвлечься от процесса добычи и заняться производством или войнами.\nВ галактике помимо людей были обнаружены Трититы, которые нападают на корабли и иногда даже перехватывают корабли, выходящие из гиперпространства. Вам необходимо тщательно следить и своевременно уничтожать Трититов, иначе от этого могут пострадать ваши торговые корабли, не обладающие оружием.\n\n<i>Запустите все добывающие предприятия и перейдите во вкладку "корабли"</i>\n'),
(22, 3, 0, '22(34) Расконсервация\n\nВ списке кораблей вы можете найти несколько патрульных катеров, сейчас эти космические корабли представляют собой сборочные модули, выделите и выберете в списке приказов "Расконсервировать" это позволит запустить процесс автоматической сборки корабля. В результате вы получите настоящие рабочие корабли.\nКорабли можно расконсервировать по одному, а можно сразу все, выбрав на главном экране количество кораблей для расконсервации.\n\n<i>Расконсервируйте все патрульные корабли</i>\n'),
(23, 3, 0, '23(34) Флот\n\nТеперь вам надо объединить корабли во флот, что бы ими было легче управлять. Для этого выделите несколько кораблей в списки (для этого воспользуйтесь клавишей Ctrl или Shift) после выделения больше одного корабля появится возможность объединить их в один флот.\n\n<i>Объедините корабли в флот</i>'),
(24, 3, 0, '24(34) Орбита\n\nЕдиным флотом вам необходимо вывести корабль на орбиту для этого выделите флот и отдайте приказ "Выйти на орбиту"\n\n<i>Выведите флот на орбиту</i>'),
(25, 3, 0, '25(34) Открытый космос\n\nНа патрульном корабле установлен радар, позволяющий находить в системе чужие корабли. Чтобы воспользоваться этим радаром, вам необходимо отвести корабль от источников гравитационного поля, для этого улетите в сторону от планеты, в любую пустую точку пространства.\n\n<i>Отлетите вашим флотом в сторону от планет</i>\n'),
(28, 2, 0, '28(34) Корабли\n\nВы изготовили свой первый космический корабль.\nНа планетарных шатлах установлены только антигравитационные двигатели, которые позволяют взлететь с планеты, для перемещения дальше орбиты необходимы корабли с межпланетными двигателями. Все корабли изготавливаются в законсервированном виде, это позволяет загружать их в транспортные корабли и перемещать как груз. Для использования корабля его необходимо расконсервировать. Процесс расконсервации доступен в меню "корабли"\n\n<i>Перейдите в меню управления кораблями</i>'),
(29, 3, 0, '29(34) Расконсервация шатла\n\nВ данном меню осуществляется все управление кораблями.\nДля начала найдите свой шатл и расконсервируйте корабль, что бы стало доступно управление кораблем.\n\n<i>Расконсервируйте шатл</i>'),
(30, 3, 500, '30(34) Первый полет\n\nТеперь можно воспользоваться кораблем и подняться на орбиту. Можно отправить корабль самостоятельно, можно выступить в роли капитана. Функциональность корабля не зависит от наличия капитана на борту, однако нельзя удаленно управлять постройками и торговлей.\nДля того, что бы переместится в корабль необходимо выбрать корабль и отдать приказ "переместиться в корабль". В ответ рядом с кораблем появится символ "*", что означает наличие капитана корабля.\nДля взлета необходимо немного времени (примерно 10 секунд) после того, как вы отдадите приказ на взлет, с поверхности планеты рядом с кораблем появится таймер, он показывает оставшееся время для выполнения приказа.\n\n<i>Переместитесь в корабль и поднимитесь на орбиту</i>\n\n<b>вознаграждение: 500</b>\n'),
(31, 3, 0, '31(34) Торговая станция\n\nПоздравляем вас с первым выходом в космос в роли капитана корабля.\nПерейдите на вкладку "Местность" и посмотрите на планету из космоса. На орбите есть несколько "точек стояния", в которых могут быть расположены различные спутники, орбитальные заводы, газодобывающие заводы и другие орбитальные объекты.\nС момента начала колонизации планеты на орбите расположена торговая станция. Постройка служит, прежде всего, защитным сооружением предоставленным конфедерацией. Любой корабль попытавшийся напасть на вашу "родную" планету будет моментально уничтожен.\nИсходя из названия понятно, что торговая станция осуществляет еще и торговую функцию. В настоящий момент на торговой станции расположены дополнительные чертежи и макет "Большого шатла", данный корабль значительно более вместительный по сравнению с малым шатлом. Необходимо доставить эти чертежи на поверхность. Для стыковки необходимо выделить точку стояния, где находится торговая станция и в левой панели во вкладке "использовать" начать стыковку.\n\n<i>Пристыкуйтесь к торговой станции</i>\n'),
(32, 3, 0, '32(34) Склад\n\nДобро пожаловать на станцию.\nНа станции хранятся чертежи и макет, их необходимо переместить на планету, это позволит изготавливать межпланетный шатл. Для управления грузом перейдите в меню Склад.\n\n<i>Перейдите в меню склад</i>'),
(33, 4, 0, '33(34) Чертежи и макеты\n\nМеню Склад позволяет перемещать товары и собственность игрока.\nСлева вверху отображаются все активные корабли игрока, под кораблями все склады, с которыми соотносится выбранный корабль. Это могут быть станции, планеты, соседние корабли, находящиеся в том же месте.\nСправа вверху отображаются окно товаров этого корабля. Если ваш корабль все еще находится на станции, выберите его в левой верхней панели, а в нижней выберите станцию. Справа внизу вы увидите список товаров для "переноса". Направление переноса определяется выбранным товаром и стрелкой. Вам необходимо перенести все чертежи и макет со склада станции на корабль.\n\n<i>Перенесите все чертежи и макет на корабль</i>\n'),
(34, 4, 3000, 'Вы закончили обучение.\n\nТеперь можно отстыковаться от станции и лететь на планету. Прилетев на планету, не забудьте выгрузить товар на склад.\nПосле этого в выпадающем списке на заводе появятся новые устройства, к которым есть чертежи, а в выпадающем списке сборочного цеха появится новый корабль "Межпланетный шатл" макет которого вы привезете.\n\nДля более быстрого развития Конфедерация выплачивает вам 10 конфедерат.\n\n<i>Летите на планету и выгрузите чертежи и макет<i>\n\n<b>вознаграждение: 3000</b>'),
(26, 3, 0, '26(34) Трититы\n\nВ списке приказов флота выберите "Переместится в системе", теперь на карте вы увидите один или несколько желтых кружков, именно так радар отмечает чужие корабли. Если вы не обнаружили таких отметок на планетарной карте, подождите, в среднем каждые 15 минут в звездную систему наведываются Трититы.\n\n<i>Найдите и уничтожьте Трититов</i>'),
(27, 3, 0, '27(34) Шатл\n\nВы справились с этим заданием, теперь можете вернуться на планету и продолжить постройку Шатла\n\n<i>Постройте свой шатл</i>');
INSERT INTO `hints` (`tid`, `text`) VALUES
('books_dtConfederates', 'Это количество конфедерат. Единственная валюта принятая для торговли редкими артефактами.'),
('books_dtCredits', 'Это количество кредитов. Кредиты это общегалактическая валюта для торговли. Принимается всеми торговыми станциями.'),
('books_dtDefence', 'В случае нападения конфедерация оценивает ваши силы и силы противника и при перевесе в сторону противника высылает свой флот на помощь вам.'),
('books_dtHomePlanet', 'Это планета которая была выбрана для колонизации. Конфедерация возлагает надежды на вас, как колонизатора.'),
('books_dtHomeStar', 'Это ваша звезда. Именно тут вас высадили корабли конфедерации. Вы можете переименовать звезду если пожелаете.'),
('books_dtInsur', 'Наличие и количество страховок. Используется для сохранения имплантантов в случае смерти.'),
('books_dtLevel', 'Это общий уровень, который показывает некоторую статистику вашей деятельности. Чем выше уровень, тем большего вы добились.'),
('books_dtLink', 'Позволяет вам пополнить счет конфедератами. Курс перевода очень зависит от способа пополнения.'),
('books_dtNewName', 'Вам необходимо выбрать новое имя. Имя должно быть уникально и не содержать оскорблений или унижений.'),
('books_dtOrbitAtack', 'Общая сила атаки с орбиты. Орбита это первая линия обороны, чем больше это число тем большие потери понесет противник в случае нападения.'),
('books_dtOrbitBuildings', 'Количество орбитальных построек. Максимальное количество построек 50. Учитывая это можно оценить занятость орбиты ее развитость.'),
('books_dtOrbitShield', 'Общая сила щитов орбиты. Вычисляется путем сложения щита каждой отдельной конструкции, на орбите щит не закрывает не военные постройки и они могут быть уничтожены.'),
('books_dtOrbitShips', 'Количество кораблей дислоцирующихся на орбите. Позволяет примерно оценить флот орбитальной обороны.'),
('books_dtOrbitWare', 'Орбитальный склад. Отображается именно <u>свободное</u> место на орбите. Как и на планете все склады связаны между собой и представляются единым складом.'),
('books_dtPlanet', 'Планета, где вы сейчас находитесь. Это местоположение непосредственно вас, как космонавта.'),
('books_dtPlanetAtack', 'Суммарна сила залпа всех планетарных военных построек. Позволяет оценить обороноспособность планеты. Чем выше число, тем больший флот может быть уничтожен.'),
('books_dtPlanetBuildings', 'Количество построек на планете. Позволяет оценить ресурс планеты. Чем больше построек, тем меньше свободного места. Так же является показателем развитости колонии.'),
('books_dtPlanetShield', 'Общая сила щитов. Чем больше щитов размещено на поверхности планеты, тем дольше продержаться войска во время атаки. Щиты помогают выиграть битву за планету.'),
('books_dtPlanetShips', 'Количество кораблей на планете. Учитываются только расконсервированные корабли. Позволяет оценить флот дислоцирующийся на планете.'),
('books_dtPlanetWare', 'Общий склад планеты. Позволяет оценить возможности хранения товара. Отображается именно <u>свободное</u> место на планете'),
('books_dtReferal', 'Если вы дадите эту ссылку вашим друзьям, то они могут принести вам прибыль. Все операции связанные с конфедератами принесут вам 10%25 в том числе окончание обучения.'),
('books_dtRename', 'Вы можете задать свое имя для планеты или звезды. Это платная услуга, поскольку потребуется регистрация во всех справочниках галактики.'),
('books_dtRobots', 'Количество роботов которые находятся в вашем подчинении. Роботы в данном случае не разделяются по типам.'),
('books_dtStar', 'Звезда, где вы сейчас находитесь. Это местоположение непосредственно вас, как космонавта.'),
('books_dtStatus', 'Это показатель ваших отношений с конфедерацией. При отрицательном значении вы станете пиратом.'),
('books_dtWar', 'Тут отражается ваш уровень военного мастерства. Он увеличивается, когда вы выигрываете битву. Уменьшается в случае вашего проигрыша.'),
('books_instance1', 'Левая панель где выводится информация о вас. Тут можно узнать ваше местоположение, а так же посмотреть основные характеристики.'),
('books_instance138', 'Позволяет перейти к игроку, что бы посмотреть информацию о нем, поменять отношение к нему или назначить вознаграждение за его голову.'),
('books_instance182', 'Запускает все добывающие сооружения на максимально возможное количество циклов. Отчет приходит в системном чате.'),
('books_instance195', 'Запускает все доступные нанодиспенсеры на планете на переработку руды. Все детали и корабли остаются в исходном состоянии.'),
('books_instance208', 'Запускает все нанодиспенсеры используя любое сырье. Это может быть руда, детали, корабли. В итоге разбирая все до элементов.'),
('books_instance221', 'Позволяет переименовать звезду или планету недопустимо использование оскорбляющих слов и выражений.'),
('books_instance23', 'Панель отношений позволяет определить кто из пилотов является вашим другом или врагом, а так же кому вы друг или враг.'),
('books_instance25', 'Панель отношений позволяет определить кто из пилотов является вашим другом или врагом, а так же кому вы друг или враг.'),
('books_instance283', 'Запускает выполнение задания. После вашего согласия задание уйдет из общего списка. Помните, что от некоторых заданий вы не сможете отказаться.'),
('books_instance296', 'Позволяет отказаться от трудного или невыполнимого задания. После вашего отказа конфедерация понизит ваш статус и несколько минут вы не сможете выполнять задания.'),
('books_instance3', 'Левая панель где выводится информация о вас. Тут можно узнать ваше местоположение, а так же посмотреть основные характеристики.'),
('books_instance30', 'Панель статистики позволяет рассмотреть общие сведения о вашей звездной системе, а так же контролировать ваши колонии.'),
('books_instance32', 'Панель статистики позволяет рассмотреть общие сведения о вашей звездной системе, а так же контролировать ваши колонии.'),
('books_instance345', 'Отдает команду на изучение. Развитие ваших навыков улучшает тот или иной показатель. Все навыки полезны, однако следует определить очередность вашего обучения.'),
('books_instance381', 'Позволяет удалить выбранные сообщения в независимости от их важности и прочитанности. Можно выделить все сообщения и затем удалить этой кнопкой.'),
('books_instance394', 'Позволяет удалить все прочитанные сообщения одним нажатием. Так же удалятся маловажные сообщения.'),
('books_instance420', 'Позволяет написать сообщение любому игроку. После того как он появится в эфире сообщение будет доставлено.'),
('books_instance46', 'Панель заданий. Позволяет выполнять небольшие миссии от конфедерации. За выполнение заданий выплачивается вознаграждение, а так же улучшается статус.'),
('books_instance48', 'Панель заданий. Позволяет выполнять небольшие миссии от конфедерации. За выполнение заданий выплачивается вознаграждение, а так же улучшается статус.'),
('books_instance509', 'Ярко зеленый цвет обозначает взаимно дружественные отношения. Темно зеленый - вы считаете его другом. Нейтральный - вас считают другом.'),
('books_instance53', 'Панель обучения. Тут вы можете изучать науки, развиваться и устанавливать имплантанты. Все это значительно улучшает ваши возможности.'),
('books_instance537', 'Ярко красный цвет обозначает взаимно враждебные отношения. Темно красный - вы считаете его врагом. Нейтральный - вас считают врагом.'),
('books_instance55', 'Панель обучения. Тут вы можете изучать науки, развиваться и устанавливать имплантанты. Все это значительно улучшает ваши возможности.'),
('books_instance565', 'Список ваших колоний. На первом месте всегда стоит ваша родная система, затем родная планета, затем все колонии.'),
('books_instance60', 'Имплантант это зачастую микрокомпьютер интегрируемый в мозг. Иногда биокомпьютер. Имплантант позволяет значительно расширить способности организма.'),
('books_instance61', 'Панель сообщений. Тут выводятся все сообщения, которые были присланы вам системой или другими пилотами. Вы так же можете ответить или написать свое сообщение.'),
('books_instance62', 'Панель сообщений. Тут выводятся все сообщения, которые были присланы вам системой или другими пилотами. Вы так же можете ответить или написать свое сообщение.'),
('books_instance683', 'Список присланных сообщейний. Слева отображается отправитель, справа краткий текст сообщения. Выделив сообщение можно прочесть его полностью.'),
('misc_dtDesc', 'Подробное описание объекта. Энциклопедия позволяет вспомнить то, что вы учили в академии дальней разведки. Это наиболее полный источник ваших знаний.'),
('misc_instance148', 'Сохраняет все выбранные настройки. Громкость музыки изменится через некоторое время после сохранения.'),
('misc_instance290', 'Список ваших роботов. Роботы часто используются на производствах для ускорения процесса. Приобрести их можно у конфедерации в любом количестве.'),
('misc_instance3', 'Громкость проигрывания музыки. При громкости меньше 10%25 музыка при входе будет отключена.'),
('misc_instance6', 'Громкость звуков и эффектов. При экономии траффика можно не трогать этот параметр, поскольку он никак не влияет.'),
('misc_instance73', 'Громкость проигрывания музыки. При громкости меньше 10%25 музыка при входе будет отключена.'),
('misc_instance74', 'Громкость проигрывания музыки. При громкости меньше 10%25 музыка при входе будет отключена.'),
('misc_instance75', 'Громкость звуков и эффектов. При экономии траффика можно не трогать этот параметр, поскольку он никак не влияет.'),
('misc_instance76', 'Громкость звуков и эффектов. При экономии траффика можно не трогать этот параметр, поскольку он никак не влияет.'),
('orbit_dtCbHeader', 'Основная характеристика объекта.'),
('orbit_dtCoord', 'Координаты выбранного объекта. Всего орбита содержит 50 точек стояния. В каждой точке можно расположить 1 орбитальную постройку.'),
('orbit_dtCount', 'Количество производственных циклов.'),
('orbit_dtDesc', 'Описание выбранной постройки. Основное назначение и некоторые характеристики.'),
('orbit_dtDgHeader', 'Пояснение к таблице. Как правило тут приводится время производства или информация об орбите в целом.'),
('orbit_dtLevel', 'Уровень постройки. Большинство построек можно улучшить до 10 уровня. Это увеличивает эффективность использования точки стояния.'),
('orbit_dtTitle', 'Наименование и уровень выбранной постройки. Большинство построек можно улучить, это позволяет эффективней использовать пространство орбиты.'),
('orbit_instance11', 'Панель улучшения. Позволяет улучшить орбитальную постройку за счет доработок и технологических улучшений.'),
('orbit_instance114', 'Запускает улучшение. Помните, что улучшение нельзя будет остановить или отменить и постройки может оказаться недоступной на время улучшения.'),
('orbit_instance125', 'Панель улучшения. Позволяет улучшить орбитальную постройку за счет доработок и технологических улучшений.'),
('orbit_instance13', 'Панель использования. Позволяет производить основные операции с постройками. Это основная панель управления.'),
('orbit_instance145', 'Выпадающий список с выбором производимого действия. Многие объекты умеют только хранить ресурсы.'),
('orbit_instance171', 'Запускает производство, переработку или добычу с использованием робота. Это позволяет использовать постройку максимально эффективно.'),
