INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(1, '<b>Автономный робот</b>\n\nРобот представляет собой автономный программный модуль, который позволяет назначать задания на заводы, карьеры, шахты и буровые. Последовательно запускает циклы, что позволяет использовать постройку с максимальной эффективностью.\n\nСрок работы измеряется в часах, 168 часов (7 дней) беспрерывной работы.\nЕсли робот лежит на складе и не используется, время не тратится.'),
(2, '<b>Автономный робот</b>\n\nРобот представляет собой автономный программный модуль, который позволяет назначать задания на заводы, карьеры, шахты и буровые. Последовательно запускает циклы, что позволяет использовать постройку с максимальной эффективностью.\n\nСрок работы измеряется в часах, 720 часов (30 дней) беспрерывной работы.\nЕсли робот лежит на складе и не используется, время не тратится.'),
(3, '<b>Обмен конфедератов на кредиты.</b>\n1 конфедерат = 10000 кредитов.'),
(4, '<b>Обмен конфедератов на кредиты.</b>\n9 конфедератов = 100000 кредитов.'),
(5, '<b>Странники</b>\n\nНеизвестная цивилизация, представители которой нигде не оставались надолго. В большинстве своем об этой цивилизации стало известно из найденных кораблей и иной техники. Корабли очень сильно напоминают стандартные человеческие корабли, от чего очень часто возникают споры между учеными. Одни ученые утверждают, что человечество это потомки Странников и мы представляем сейчас лишь очередной виток истории и эволюции одного и того же вида. Другие ученые утверждают, что Странники являются потомками человечества, которые по непонятным причинам совершили скачек в прошлое во времени. Нередко встречаются корабли точное устройство которых не поддается анализу, однако всегда есть возможность использовать такой корабль.\nУже доподлинно известно, что управление кораблем создано для человекоподобной расы, такого же среднего роста с тем же количеством конечностей, с теми же голосовыми и визуальными рецепторами.\n\nВ кораблях Странников настолько все очеловечено, что нельзя это списать на случайность. Либо корабли специально конструировались для человека и потом подброшены нам ради какого-то эксперимента, либо корабли конструировались для Странников, но тогда Странники это те же люди, по крайней мере телом.\n\nНекоторые корабли содержали чертежи и макеты, после тщательного изучения монокристаллов стало понятно, что эта технология полностью совпадает с технологией людей, однако устройства странников (не смотря на то, что их можно произвести) не поддаются доработке или копированию. Некоторые молекулярные связи в приборах и корпусах специально собраны на "неизвлекаемость", при попытке разобрать такое устройство оно самоликвидируется практически без выделения энергии.\n\nЗа неимением отрицательных данных конфедерация поддерживает Странников.\nПри попытке контакта рекомендуется проявлять максимальное терпение и сдержанность.\n\nВ случае обнаружения корабля Странников с членами экипажа на борту стоит немедленно обратится в конфедерацию и ожидать дальнейших инструкций.'),
(6, '<b>Страховка конфедерации</b>\n\nКонфедерация предлагает застраховать невосполнимую собственность. Страховка действует до момента смерти. В случае вашей смерти вам вернут все имплантанты, однако страховка будет аннулирована. Не забывайте вовремя оформить страховку и вы никогда не потеряете имплантанты. Есть возможность купить несколько страховок "на перед", однако не забывайте следить за состоянием страховок.'),
(7, '<b>Защита конфедерации</b>\n\nЗа определенную сумму конфедерация готова разместить свой флот недалеко от вашей системы. В случае нападения на орбиту планеты с установленной защитой конфедерация выставит свой флот на подмогу.\nСтоит учитывать, что конфедерация не будет выдвигать свой флот без явной опасности для орбитальных строений. Если по расчетам конфедерации защита устоит, то флот не вылетит на подмогу. Однако при явном перевесе в силе выдвигается флот заведомо сильнее нападающего. После атаки на вашу планету флот будет оставаться на орбите еще 3 дня в режиме охраны. Все корабли противников конфедерации будут уничтожены. Через три дня после атаки флот покинет свою позицию.\nЗащита конфедерации достаточно дорогое удовольствие, однако позволяет себя обезопасить от действительно сильного нападения. Если у вас нет орбитальной обороны, конфедерация сама по себе не будет защищать вашу планету.\nКонфедерация не пошлет свой флот на защиту пиратов, даже если она была оплачена еще до того, как вы стали пиратом - флот вылетать не станет. Однако и защита не будет снята с планеты и как только статус в обществе будет положительным защита начнет работать.'),
(23, '<img src="img/karier2.png"><b>Карьер</b>\n\nПозволяет добывать полезные ископаемые с поверхности планеты. Одно из первых зданий, которое должно быть построено для планомерного развития. Для постройки необходим <font color="#00FFFF">Нанодиспенсер</font>\nС каждым новым уровнем усовершенствования увеличивается количество циклов производства. Начальный уровень 1 цикл, максимальный уровень 10 циклов. Для безостановочного производства необходимо использовать автономных роботов, необходима лицензия земной конфедерации.\n\nСклад для хранения добытых полезных ископаемых: 1000\nНачальное время постройки: 60 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 10'),
(24, '<img src="img/dispancer2.png"><b>Нанодиспенсер</b>\n\nПереплавляет ископаемые, и ненужные устройства в ресурсы. Производство работает за счет применения наноботов, наноботы расщепляют вещества на составляющие атомы, из которых впоследствии можно изготавливать различные устройства. Качество переплавки зависит от уровня структуры. Первое производственное здание, которое необходимо построить на планете.\nГотовые сложные устройства, собранные в сборочном цехе не поддаются переплавке ввиду их больших размеров. Переплавка и расщепление можно производить только на планетарном уровне, аналогичных строений орбитального базирования нет.\nДля постройки необходимо наличие <font color="#00FFFF">Электростанции</font>\nСклад для хранения добытых полезных ископаемых: 1000<br>Начальное время постройки: 120 секунд, уменьшается при изучении науки "Строитель"'),
(25, '<img src="img/laboratory_2.png"><b>Лаборатория</b>\n\nИспользуется для исследования устройств, что позволяет с определенной долей вероятности получить чертеж исследуемого устройства необходимый для изготовления аналогичных устройств. Время исследования зависит от устройства. Некоторые устройства невозможно исследовать в принципе, ввиду недостаточного технического развития, это относится к сложным устройствам, а так же к артефактам иных цивилизаций. Для постройки требуется <font color="#00FFFF">сборочный цех</font>\n\nВ лаборатории можно изготавливать копию чертежа, время изготовления копии зависит от сложности чертежа. Некоторые чертежи облагаются лицензией, ввиду чего копирование таких чертежей невозможно.\n\nБолее высокий уровень структуры обеспечивает большую вероятность изготовления чертежа из устройства. Начальный уровень вероятности 20 процентов, максимальный уровень 80 процентов, гарантию изготовления чертежа до окончания исследования получить невозможно. Устройство, которое отдается на исследование, теряется в любом случае, однако в случае удачи, при наличии чертежа можно изготовить другое.\n\nСклад для хранения добытых полезных ископаемых: 500\nНачальное время постройки: 180 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 35'),
(26, '<img src="img/capsule.png"><b>Капсула</b>\n\nКосмическая капсула в которой вы спустились на планету. В капсуле установлено устройство обучения и сканирования нейронной сети, а так же полный комплект регенерирующей машины. Это позволяет восстанавливать тело и память вплоть до момента смерти. Капсула не может быть уничтожена или улучшена.'),
(27, '<img src="img/rocket.png"><b>Ракетная защита</b>\n\nРакетная защита, как и все военные постройки, не требует ничего для строительства. Собственные генераторы позволяют вырабатывать достаточное количество энергии для радара и орудий. Производство снарядов происходит на внутреннем заводе и не требует вмешательства. Ракеты являются самым слабым защитным оружием, однако при улучшении постройки можно запускать корабельные ракеты. Максимальный тип ракет зависит от уровня постройки.\n\nТТХ:\nСила выстрела: 2\nКол. выстрелов: 1\nМаксимальный тип ракет = ( уровень постройки - 1 )'),
(28, '<img src="img/laser.png"><b>Лазерная защита</b>\n\nЛазерная защита, как и все военные постройки, не требует ничего для строительства. Собственные генераторы позволяют вырабатывать достаточное количество энергии для радара и орудий. Лазер используется против малых кораблей, обладая огромным количеством выстрелов способен уничтожить значительный флот противника одним залпом. Прежде всего, уничтожаются транспортные корабли, не обладающие щитом.\n\nТТХ:\nСила выстрела: 5\nКол. выстрелов: 10 на каждый уровень\nСклад для хранения добытых полезных ископаемых: 0\nНачальное время постройки: 1800 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 0'),
(29, '<img src="img/plasma.png"><b>Плазменная защита</b>\n\nПлазменная защита, как и все военные постройки, не требует ничего для строительства. Собственные генераторы позволяют вырабатывать достаточное количество энергии для радара и орудий. Плазма представляет собой сгусток ионизированного газа с очень высокой внутренней энергией. В момент выстрела плазма направляется по каналу ствола магнитным полем.\n\nТТХ:\nСила выстрела: 75\nКол. выстрелов: 1 на каждый уровень'),
(30, '<img src="img/maser.png"><b>Коротковолновый мазер</b>\n\nКоротковолновый мазер, как и все военные постройки, не требует ничего для строительства. Собственные генераторы позволяют вырабатывать достаточное количество энергии для радара и орудий. Мазер представляет собой волновое оружие, излучающее СВЧ волны смешанного диапазона. Оружие обладает большой проникающей способностью, что позволяет атаковать противника группой. При этом слабые корабли сгорают под действием оружия, сильные корабли теряют часть щита.\n\n\nТТХ:\nСила выстрела: 1 на каждый уровень\nКол. выстрелов: по всем целям одновременно\nСклад для хранения добытых полезных ископаемых: 0\nНачальное время постройки: 1200 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 0'),
(31, '<img src="img/shield.png"><b>Планетарный щит</b>\n\nПланетарный щит, как и все военные постройки, не требует ничего для строительства. Собственные генераторы позволяют вырабатывать достаточное количество энергии для щита. Щит не наносит урона противнику, однако поглощает любой импульс энергии направленные в сторону планеты. Таким образом, во время атаки в первую очередь страдают именно щиты. После боя щит полностью восстанавливается. Рекомендуется как минимум одно такое сооружение для обороны планеты, это позволит предотвратить массовую бомбардировку планеты с уничтожением гражданских построек.\n\nТТХ:\nЩит: 1000 на каждый уровень'),
(33, '<img src="img/factory2.png"><b>Завод</b>\n\nИспользуется для изготовления устройств и деталей. Для производства необходимы полезные ископаемые в виде материалов, а так же чертеж устройства, которое изготавливается. Чертежи приобретаются, копируются в Лаборатории или производятся из исследования устройств. Каждое устройство для производства требует времени. Для постройки необходим Нанодиспенсер\nС каждым новым уровнем усовершенствования увеличивается количество циклов производства устройства. Начальный уровень 1 цикл, максимальный уровень 10 циклов. Для безостановочного производства необходимо использовать автономных роботов, необходима лицензия земной конфедерации.\n\nСклад для хранения полезных ископаемых и произведенных деталей: 5000\nНачальное время постройки: 60 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 50\n'),
(34, '<img src="img/electro_2.png"><b>Электростанция</b>\n\nДобывает электроэнергию из солнечного света, ветра, а так же верхних слоев атмосферы. Для постройки не требуется никаких зданий.\nБолее высокий уровень структуры обеспечивает большее количество энергии. Начальное количество производства энергии 100 единиц. Энергия производится не циклами, а постоянно.\nСклад на структуре: 0<br>Начальное время постройки: 60 секунд, уменьшается при изучении науки "Строитель"'),
(36, '<img src="img/mine2.png"><b>Шахта</b>\n\nПозволяет добывать полезные ископаемые со среднего слоя планеты. Для постройки обязательно исследование среднего слоя планеты. Для постройки необходим <font color="#00FFFF">Нанодиспенсер</font>\nС каждым новым уровнем усовершенствования увеличивается количество циклов производства. Начальный уровень 1 цикл, максимальный уровень 10 циклов. Для безостановочного производства необходимо использовать автономных роботов.\nСклад для хранения добытых полезных ископаемых: 1000<br>Начальное время постройки: 120 секунд, уменьшается при изучении науки "Строитель"'),
(37, '<img src="img/burovaya_2.png"><b>Буровая</b>\n\nПозволяет добывать полезные ископаемые с глубинного слоя планеты. Для постройки обязательно исследование глубинного слоя планеты. Для постройки необходим <font color="#00FFFF">Нанодиспенсер</font>\nС каждым новым уровнем усовершенствования увеличивается количество циклов производства. Начальный уровень 1 цикл, максимальный уровень 10 циклов. Для безостановочного производства необходимо использовать автономных роботов.\n\nСклад для хранения добытых полезных ископаемых: 1000\nНачальное время постройки: 240 секунд, уменьшается при изучении науки "Строитель"\nПотребление энергии: 60'),
(38, '<img src="img/silo.png"><b>Склад</b>\n\nИспользуется для хранения любых полезных ископаемых, минералов и продукции. Количество свободного места определяется уровнем постройки. Чем выше уровень постройки, тем глубже расположены отсеки хранения, поэтому каждое новое усовершенствование обходится дороже предыдущего.'),
(39, '<img src="img/asemble2.png"><b>Сборочный цех</b>\n\nИспользуется для изготовления сложных устройств из деталей, произведенных на <font color="#00FFFF">Заводе</font>. Для производства необходимы детали, а так же макет устройства которое изготавливается. Макеты приобретаются или копируются в <font color="#00FFFF">Лаборатории</font>. Каждое устройство для производства требует времени. Для постройки необходим <font color="#00FFFF">Завод</font>\nС каждым новым уровнем усовершенствования увеличивается количество циклов производства устройств. Начальный уровень 1 цикл, максимальный уровень 10 циклов. Для безостановочного производства необходимо использовать автономных роботов, необходима лицензия земной конфедерации.\nСклад для хранения полезных ископаемых и произведенных деталей: 5000<br>Начальное время постройки: 420 секунд, уменьшается при изучении науки "Строитель"'),
(50, '<b>Конспект по обучению</b>\n\nВо время длительных перелетов человеческий организм погружается в анабиоз, что накладывает отпечаток на память. После анабиоза человек знает все, чему его учили, но из-за ослабленных синапсных связей не может это вспомнить. По сути обучение представляет собой восполнение связей в нейронной сети головного мозга и из-за этого не может быть прервано. Каждый последующий уровень обучения затрагивает все более и более ослабленные нейроны, что бы не вызвать неприятных последствий производится более щадящим способом и требует больше времени на восстановление. Полный курс восстановления разбит на 10 этапов, что позволяет без труда рассчитывать время необходимое для восстановления.\n\nОбучение некоторым наукам невозможно без восполнения сопутствующих знаний. Некоторые знания не преподавались в принципе и поэтому их изучение требует еще большего времени.\n\nОсновные знания, которые доступны для обучения:\nГеолог - Позволяет использовать геологические приборы.\n 3 - Шахтер - Сокращает время добычи ресурсов.\n     3 - Металлург - Сокращает время переплавки ископаемых.\n         3 - Производственник - Сокращает время производства различных деталей.\n             3 - Инженер - Увеличивает вероятность создания чертежа по образцу.\n                 5 - Навигатор - Сокращает время перелета между двумя точками пространства.\n                     3 - Гипернавигатор - Сокращает время перелета в гиперпространстве.\n                     5 - Бомбардир - Увеличивает точность попадания при атаке планеты.\n                         5 - Абордаж - Увеличивает вероятность абордажа.\n                 5 - Снайпер - Позволяет реже промахиваться в космическом бою\n                 7 - Тактик - Определяет очередность кораблей с которых производится выстрел\n                 7 - Стратег - Определяет очередность кораблей и построек по которым производится выстрел\nСкорочтение - Сокращает время изучения других наук\nСтроитель - Сокращает время постройки объектов\n 3 - Технолог - Увеличивает время и количество добычи любого минерала.\n     10 - Технолог карьеров - Увеличивает время и количество добычи минералов с верхнего слоя.\n     10 - Технолог шахт - Увеличивает время и количество добычи минералов со среднего слоя.\n     10 - Технолог буровых - Увеличивает время и количество добычи минералов с глубинного слоя.\n     10 - Технолог орбитальных заводов - Увеличивает время и количество добычи газа на орбитальных газодобывающих заводах.'),
(51, '<b>Конспект по геологии</b>\n\nПолезные ископаемые расположены на трех равных по площади слоях планеты.\n\n<i>Поверхность</i> - Выделяется разной раскраской, что позволяет определить состав минералов. Добыча осуществляется карьером. Скорость добычи большая. Минералы стандартной группы. Наибольшую важность представляют собой железо и кремний, как основные материалы для строительства. На втором месте по значимости расположены медь и титан. Если есть выбор добывать минерал с поверхности или с среднего слоя, стоит всегда отдавать предпочтение поверхности, поскольку скорость добычи материалов как правило окупает низкое процентное содержание.\n\n<i>Средний слой</i> - Наполнен минералами малого и редкого содержания. Минералы в слое расположены абсолютно хаотично. Для получения сведений о содержании минералов необходимо "усовершенствовать" точку на планете используя "геологический зонд" или построить "геологический спутник". Каждый зонд исследует 1 слой поверхности, Спутник проводит исследования на 5-м уровне. Средний слой представляет собой компромисс между редкими минералами и длительной добычей. Для разработки используются шахты. Средний слой обладает лучшей скоростью добычи по сравнению с глубинным слоем. В случае выбора стоит отдавать предпочтение среднему слою.\n\n<i>Глубинный слой</i> - Наполнен редкоземельными минералами. Минералы в слое расположены абсолютно хаотично. Для получения сведений о минералах необходимо использовать 2 "геологических зонда" в одной и той же точке или развить "геологический спутник" до 10 уровня. Добычу проводят при помощи буровой. Добыча минералов из глубинного слоя достаточно длительный процесс, а содержание редкоземельных веществ как правило не превышает 5%25 от породы.\n\nПродажа или использование породы в чистом виде практически не встречается, для получения чистых химических элементов используется нанодиспенсер. Скорость обработки материала не зависит от его объема. Нельзя обрабатывать разные материалы одновременно. Нельзя назначать робота обрабатывать материалы, поскольку переработка может уничтожить (разобрать) полезные детали и корабли.\n\nПустая планета (без построек) обладает складом 500, что позволяет выгрузить железо, кремний и медь для начала колонизации.\n\nЭкономически выгоднее исследовать планеты при помощи зондов, поскольку спутник обходится дороже, однако после исследования спутник можно снести, и получить обратно половину потраченных материалов. Однажды разведанное месторождение остается разведанным навсегда. Спутник к тому же достаточно менее затратное по времени устройство.\n\nНекоторые материалы, такие, как Тритий, нельзя получить из минералов, однако его можно получить в результате переработки.\n\nСводная таблица распространенности материалов:\nКислород	1725\nКремний		464\nСера			277\nЖелезо		275\nКальций		226\nМедь			208\nМарганец	202\nАлюминий	172\nРтуть		170\nЦирконий	157\nСеребро		154\nТитан		125\nУглерод		124\nВольфрам	123\nТеллур		115\nНатрий		107\nМышьяк		100\nСвинец		95\nХлор			92\nВодород		89\nУран			88\nМагний		86\nВисмут		80\nЗолото		77\nЦинк			76\nМолибден	60\nСтронций	59\nФтор			50\nКобальт		47\nКалий		42\nНикель		34\nОлово		31\nФосфор		30\nСурьма		24\nРубидий		21\nХром			21\nТорий		16\nЦезий		16\nСамарий		14\nГадолиний	14\nБор			10\nАзот			9\nСелен		8\nГерманий	7\nНеодим		6\nВанадий		5\nБериллий	5\nЛитий		2\nДейтерий	1\nИттрий		1'),
(52, '<b>Конспект по планетоведению</b>\n\nПланеты галактики состоят из 4-х типов планет.\n1. Газовые гиганты, добывается Водород, красного цвета\n2. Планеты земного типа, добывается Кислород, зеленого цвета\n3. Высохшие планеты добывается Азот, желтого цвета\n4. Мертвые планеты добывается Хлор, белого цвета\nПри строительстве орбитальных газодобывающих заводов вокруг каждой планеты добывается свой собственный газ.\n\nДля колонизации выбирается планета земного типа как наиболее пригодная для жизни. Однако в процессе колонизации не запрещается осваивать природные ресурсы других планет. Конфедерация не несет никакой ответственности за колонизацию иных планет, а соответственно не обеспечивает охраной.\n\nЛюбая планета имеет 4 линии обороны.\n1. Корабли на орбите планеты\n2. Орбитальные средства защиты\n3. Корабли на поверхности планеты\n4. Планетарные защитные сооружения.\n\n<i>Газовые гиганты</i>\nГигантские планеты в сотни и тысячи раз больше обитаемых планет. Не обладают твердой поверхностью как таковой, имеют очень высокий процент выветривания, что позволяет добывать на их орбите водород для заправки кораблей. Нередко газовые гиганты становятся пристанищем для пиратских баз, легкий доступ к топливу и большое количество планет этого типа позволяет легко затеряться в просторах космоса.\n\n<i>Планеты земного типа</i>\nОчень редкие планеты в составе звездных систем. Как правило в звездной системе существует только одна планета этого типа. Колонисту предоставляется полная свобода действий на поверхности этой планеты и гарантируется полная неприкосновенность. Однако на планетах этого типа не всегда можно найти достаточное количество минералов и со временем приходится разрабатывать другие планеты. Некоторые минералы содержат мизерное количество редкоземельных материалов. Однако количество добывающих сооружений ограничено количеством ископаемых на планете.\n\n<i>Высохшие планеты</i>\nПланеты раньше были очень похожи на землю, содержали кислородную атмосферу и возможно там существовала жизнь, однако до сих пор не было найдено ни одной планеты этого типа на которой обнаружились бы проявления разумной жизни. Некоторые постройки были сделаны пришельцами извне, поскольку носили высокотехнологичный уровень и не имели предшествующих развитию построек. Раса пришельцев зовется условно "Странники", поскольку их никто никогда не видел, но были найдены не однократно подтверждения их присутствия во вселенной. Остатки органики образуют азотную атмосферу, газодобывающие заводы располагаются в верхних ее слоях и получают азот в чистом виде.\n\n<i>Мертвые планеты</i>\nКак правило планеты образуются из-за близости к светилу либо это бывшие крупные астероиды или кометы. Планеты образуют слабую оболочку из хлора, но из-за слабой гравитации орбита планеты может стать пристанищем для нескольких заводов по сбору хлора.'),
(53, '<b>Конспект по строительству</b>\n\nЛюбое здание, построенное на планете, создается из сложного молекулярного сплава кремния и железа. Это основные элементы необходимые для постройки. Некоторые сложные строения, такие как охранные сооружения, содержат очень редкие материалы. Для большинства зданий необходима энергия, однако потреблять энергию они начинают только после постройки. Количество энергии зависит от количества и уровня электростанций на планете. Каждое строение призвано выполнять только свою функцию, однако во многих помещениях пустое пространство используется под складирование материалов.\n\nЕсли на планете нет ни одного здания, на планету можно выгрузить 500 единиц. В отличии от орбиты на поверхности нет возможности использовать материал из трюма кораблей.\n\nВ случае сноса постройки на склад возвращается половина ресурсов, потраченных на строительство и улучшение постройки. На одной точки поверхности может быть установлено только одно здание, что ограничивает поселенца на малых планетах.\n\n<i>Этапы развития</i>\nПрежде всего необходимо добыть Железо и Кремний, именно эти составляющие позволят планомерно застраивать всю планету. Следующий по необходимости материал это Медь. Стоит всегда следить за оставшейся энергией, постройки начинают потреблять энергию в момент окончания строительства. Любой процесс запущенный на планете не остановится, если закончится энергия, однако запустить новый процесс не получится.\n\nЛюбая гражданская постройка не содержит укрепленных конструкций и может быть легко разрушена в случае атаки на планету. Для защиты планеты следует использовать планетарный щит. Это устройство окружает всю планету непроницаемым барьером. В случае атаки на планету это единственное средство планетарной защиты.\n\nДля того, что бы отразить атаку противника так же следует строить активные оборонительные сооружения, такие как Лазерная защита, Плазменная защита, Квантовый генератор. Любая постройка улучшает свои характеристики с улучшением уровня. Некоторые характеристики схожи при дублировании, например два карьера 5 уровня добывают столько же материала как 1 карьер 10-го уровня, однако 2 карьера тратят в 2 раза меньше времени на добычу ресурсов, а 1 карьер 10-го уровня обойдется дороже в развитии.\n\nЛюбое улучшение первого уровня требует 1/4 часть ресурсов необходимых для постройки. Второй уровень обходится в 1/2, третий в 3/4, четвертый потребует ровно такое же количество ресурсов как новая постройка. Однако не стоит забывать, что есть характеристики, которые можно получить только улучшая постройки, так например Нанодиспенсер 10-го уровня перерабатывает руду с КПД 99%25, то есть масса материала практически не теряется за время обработки. 99%25 это максимально возможное КПД.');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(54, '<b>Конспекты по кораблестроению</b>\n\nКораблестроение это одна из основных отраслей развития колонии, космические корабли позволяют вести торговлю, исследовать вселенную и вести военные компании.\n\nПервостепенное назначение кораблей это доставка грузов. Большинство кораблей обладает грузовым отсеком, однако при перевозке груза следует учитывать, что кораблю необходимо топливо.\n\nВсе корабли снабжаются различными двигателями, существует всего три основных типа двигателей:\n\n<i>Антигравитационный двигатель</i> - он не потребляет топливо, но позволяет легко и быстро преодолеть путь в атмосфере планеты. На любом корабле, который способен приземлиться на планету, установлен этот тип двигателей. Конструктивная особенность двигателя не позволяет устанавливать его на большие корабли, поскольку действие гравитационного и антигравитационного поля создают слишком большое напряжение на корпус корабля.\n\n<i>Двигатель планетарного типа</i> - сейчас существует несколько двигателей на принципе разгона материи с последующим использованием разницы в кинетической энергии разгонного тела. Существуют маломощные ионные двигатели не потребляющие топлива, существуют диффузные двигатели в которых разгонным телом служит ионизированный водород. Данный тип двигателя установлен практически на всех космических кораблях, за исключением орбитальных шатлов. Двигатели потребляют водород в зависимости от массы корабля и скорости разгона.\n\n<i>Гиперпространственный двигатель</i> - Во время экспериментов с сильными магнитными и гравитационными полями ученые обнаружили свойство пространства скачкообразно менять размерность. Сначала удалось реализовать пятимерное пространство, а затем и большее количество измерений. Изменения в пространстве сохраняются некоторое время и тесты показали, что с увеличением размерности пространства увеличивается максимальная скорость с которой может перемещаться масса. При достижении семимерного пространства скорость стала неограниченной и рост массы при ускорении не наблюдался вовсе. Это позволило создать гиперактивный двигатель, в основе которого лежит принцип резкого изменения пространства с последующим перемещением с неограниченной скоростью. При выходе в обычное пространство корабль должен находиться в состоянии покоя, иначе произойдет непредвиденное перемещение во времени. Гипрепространственные двигатели потребляют уран для перемещения, производя большое количество энергии из управляемого ядерного взрыва.\n\nКрупные корабли обладают слабой внутренней конструкцией и не могут приземлиться на планету, их просто расплющит под собственным весом во время посадки. При этом такой корабль можно построить на поверхности и использовать как планетарную крепость. Крупные корабли состоят из нескольких модулей и собираются непосредственно на орбите. Любой модуль массой больше 10000 необходимо собирать на орбите, иначе его нечем будет вывести с планеты.\n\n<i>Транспортные корабли</i> - обладают малым расходом топлива и большой грузоподъемностью, однако по скорости они самые медленные корабли во вселенной. Не стоит забывать про Трититов, которые могут перехватить транспортный корабль на выходе из гиперпространства, всегда следует собирать транспортный флот с военным кораблем. Для защиты от Трититов достаточно одного истребителя.\n\n<i>Военные корабли</i> - обязательно содержат щит или броню и обладают огневой мощью. Для простоты военное вооружение можно разделить на три типа: лазерное, плазменное и квантовое. Лазерное оружие обладает малой мощностью, но способно наносить множественные удары по кораблям противников. Плазменное оружие обладает огромной мощностью. Но против малых кораблей не эффективно, потому что после уничтожения корабля остается запас мощности улетучивающийся в космос. Квантовое оружие обладает малой мощностью, но наносит поражение всем кораблям противника одновременно, в независимости от их количества.\n\n<i>Специальные корабли</i> - существует несколько специальных кораблей которые не относятся к общим классам. Прежде всего это радарные корабли, которые могут обнаружить чужие корабли в обычном пространстве. Радарные корабли - используются для поиска потерянных кораблей, для охоты на трититов и для поиска чужаков в своей звездной системе. Гиперперехватчики - используются для экономии топлива в торговых операциях, а так же пиратами для нападения на транспортные корабли выходящие из гиперпространства. Авианосцы - по своей сути являются огромными транспортными кораблями которые способны в одиночку перевозить несколько других кораблей.'),
(55, '<b>Конспект по исследованиям</b>\n\nИсследования - это одно из направлений для развития колоний. Прежде всего исследования позволяют сэкономить средства колониста. Некоторые чертежи удается расширить и улучшить, некоторые чертежи удается просто скопировать, а учитывая нулевой вес чертежа легко доставить его на другую планету. Некоторые чертежи не поддаются копированию и доработке, ввиду сложной конструкции агрегата.\n\nИмеется возможность изготовить чертеж имея только само устройство, однако некоторые устройства не поддаются исследованию из-за применения неизвестных до сих пор технологий, а так же из-за применения специальных приемов сокрытия конструкций. Во время исследования агрегат подвергают различным осмотрам во всех спектрах радиочастот, после чего следует молекулярное исследование, разбирающее чертеж до последнего атома. Во время исследования нельзя точно предугадать результат, всегда существует возможность потерять деталь и не получить чертеж.\n\nКопирование чертежей всегда завершается удачно, однако чертежи которые нельзя скопировать можно только купить.\n\nДоработать можно только те устройства, чертежи которых имеются у исследователя. Доработка не улучшает характеристики безвозмездно, происходит подмена одних характеристик другими, так устанавливая дополнительное вооружение как правило уменьшается свободное место в трюме. На некоторых кораблях удается заменить высокопроизводительные водородные двигатели медленными, но экономными ионными двигателями.'),
(56, '<b>Конспект по торговле</b>\n\nДля торговли у каждого колониста есть торговая станция. На станции установлен гиперпередатчик, благодаря которому торговый компьютер получает информацию даже с самых удаленных планет.\n\n<i>Торговый компьютер</i>\nУстройство представляет собой статистический список товаров продаваемых в галактике. В первом столбце отображается наименование товара, далее экран условно можно разделить на две равные части. Левые 4 столбца относятся к продаже товара. Правые 4 столбца относятся к покупке товара. Если вы хотите заработать на торговле, вам необходимо найти планету, где цена товара на продажу ниже цены товара на покупку. Компьютер отмечает такие сделки зеленым цветом.\nУчтите, во время вашего полета вас могут ограбить пираты или на ваш корабль могут напасть Трититы. Настоятельно советуем сопровождать транспортный корабль хотя бы одним истребителем.\n\n<i>Продажа или покупка товара на своей станции</i>\nДля продажи или покупки товара необходимо переместиться лично на станцию и зайти в меню Местность. Слева будут указаны все существующие сделки, справа необходимо сначала выбрать товар в верхнем выпадающем списке, затем назначить цену на покупку или продажу, выбрать количество товара для покупки или продажи и сохранить изменения.\n\nЧто бы продать(купить) что-то на своей станции:\n1.Выбрать товар справа вверху\n2.Назначить цену продажи(покупки)\n3.Указать количество товара для продажи(покупки)\n4.Сохранить настройки.\n\nЕсли вы покупаете товар, деньги на вашем счете сразу блокируются. Если вы продаете товар, то блокируется товар. Продавать и покупать товар можно только за кредиты.\n\nРазрешается выставлять товар одновременно и на продажу и на покупку, при этом продаваемый товар будет приносить прибыль, покупаемый товар будет откладываться на складе станции.\n\nМожно выставлять товар на покупку даже если этого товара нет нигде в галактике, на продажу можно выставлять только тот товар, которые есть на станции на момент продажи.\n\n<i>Продажа и покупка товара на чужой станции</i>\nДля торговли необходимо:\n1. Пристыковаться любым вашим кораблем к станции на которой осуществляется продажа или покупка товара.\n2. Зайти в меню Торговля - Покупка/Продажа.\n3. В списке кораблей выбрать свой корабль.\n4. В списке товара выбрать товар.\n5. Написать количество и осуществить покупку или продажу товара.\n  Вместо количества можно использовать "Купить полностью" и "Продать полностью" - тогда сделка осуществится на максимальное количество товара.\n\n<i>Торговля с дельфинами</i>\nВ галактике существует раса разумных дельфинов. Никто не знает откуда они появились, они не вступают в конфликты, не обращают внимание на статус или боевые заслуги. Все, что их интересует это прибыль. Если вы продаете что-то дешевле чем кто-то покупает, будьте уверены рано или поздно к вам прилетят дельфины. Они летают на очень медленных кораблях, однако всегда производят моментальную куплю-продажу. У ученых есть только одна теория на этот счет, что на самом деле летят не два корабля, а один - просто он одновременно находится в двух точках вселенной одновременно. Как только на одной станции происходит покупка, на другой станции осуществляется продажа. Принцип работы этого механизма не изучен, захваченные корабли не проявляют таких свойств. Возможно дельфины как-то осуществляют переброску товара используя свои способности.'),
(57, '<b>Военное дело</b>\n\nДлительность боя зависит от количества кораблей и их мощности.\n\nБой состоит из волн, одна волна - это когда оба противника сделали все выстрелы из всех кораблей.\nВолна состоит из залпов. Залпы чередуются до тех пор, пока есть не стрелявшие корабли с обоих сторон.\n\nПервым стреляет атакующая сторона, в зависимости от навыка Тактик выбирается корабль который будет производить залп. Затем в зависимости от навыка Стратег определяется цель для выстрела из орудия и производится выстрел. Если после выстрела противник остался в живых второй выстрел производится по той же цели. Если после выстрела противник уничтожен или захвачен, выбирается следующий противник. Когда залп (все выстрелы с корабля) закончены, ход переходит обороняющейся стороне.\n\nОдин ход занимает 1 секунду, если у одной из сторон не осталось кораблей, то все оставшиеся корабли стреляют по очереди без перехода хода. Когда с обоих сторон все корабли выстрелили, начинается вторая волна.\n\nБой длится до тех пор, пока с одной из сторон не останется кораблей (построек)\n\nПри атаке на планету учитывается навык Бомбардир. В случае низкого уровня будет очень большой разброс от цели, что может привести к полному уничтожению всех построек. При высоком уровне поражаются только военные объекты.\n\nПланетарный щит окружает всю планету непроницаемой оболочкой, таким образом, пока энергия щита не истощится, ни одна постройка не пострадает. Если щитов несколько их энергия будет кончаться последовательно (сначала выйдет из строя первый щит, затем второй и т.д.)\n\nЛюбой щит (планетарный или щит корабля) восстанавливается после окончания всех боев. Если нападение идет несколькими флотами подряд, при этом первый бой еще не закончился и второй бой уже начался, щиты между боями не восстановятся.\n\nЕсли на корабле есть ракеты, то вместе с первым выстрелом в залпе вылетит ракета. Если на корабле есть несколько типов ракет, первой вылетит та ракета, количество которых больше. Если количество равное, то первой вылетит более слабая ракета.\n\n<b>Методы атаки:</b>\n<i>Планеты</i>\nПланеты атакуются с орбиты. Стрелять могут все корабли, однако корабли без антигравитационного двигателя не могут подойти близко к поверхности и вынуждены стрелять прямо с орбиты, от этого страдает мощность выстрела. До планеты доходит лишь 10%25 от выстрела. При этом главным навыком будет "Бомбометание", данный навык определяет разброс от попадания. При 0 уровне снаряд отклоняется в любую сторону на 10 позиций. Таким образом обстреливается квадрат 20 на 20 в случайном порядке. Это приводит к уничтожению практически всех объектов в этом квадрате. При уровне бомбометания 10 уничтожаются только военные цели, снаряды и выстрелы не отклоняются от траектории прицеливания.\nПрежде всего на планете уничтожается планетарный щит. Если щитов несколько они уничтожаются последовательно один за другим. Затем уничтожаются военные постройки. Если на планете нет ни одной военной постройки планета считается захваченной.\nВсе корабли на планете могут быть выставлены в режим охраны, таким образом планета будет защищена с двух фронтов. Однако флот на планете не находится под защитой щита и будет атаковаться как обычный флот (или корабль)\n\n<i>Орбита</i>\nОрбита атакуется при подлете. Если в момент перемещения к планете не было написано "атаковать орбиту", то орбита считается незащищенной и подлет разрешен. Однако если во время перелета корабля владелец построек на орбите включит защиту, корабль подлетающий к планете не будет извещен об этом. В таком случае подлетающий корабль будет сразу же атакован.\nПри атаке используются все корабли флота, при этом корабль может так же промазать мимо военного объекта. Учитывается так же навык Бомбардир. Атаковать орбиту можно как из космоса, так и с планеты (вариант блокады планеты) при этом взлетающие корабли будут предупреждены об установленной охране на орбите. На орбите нет аналога щита, таким образом сразу начинается разрушение военных построек.\nЕсли на орбите есть флот в режиме охраны, то флот будет атакован вместе с орбитой. При этом нападающий получит преимущество по мощности, но проиграет во времени. Два боя идут более быстротечно и активно.\n\n<i>Другой флот или корабль</i>\nПри атаке корабля на корабль учитываются навыки Стратег и Тактик.\n\nКорабли можно использовать как охранное сооружение, для этого достаточно установить у корабля "Режим охраны" в этом случае корабль будет нападать на все приближающиеся корабли других колонистов. Необходимо очень осторожно относится к этому режиму, есть вероятность, что вы атакуете невинный корабль.\n\n<b>Захват кораблей</b>\nЕсли во время боя у корабля истощился щит - есть вероятность проникновения абордажной команды. В случае успеха корабль переходит на сторону противника вместе со всем содержимым трюма. Вероятность абордажа зависит от навыка Абордаж. Каждый уровень навыка дает 2%25 вероятности успешного абордажа. У пиратов всегда есть вероятность абордажа, которая зависит от статуса в обществе. Вероятности навыка Абордаж и пиратства складываются.\nУровень абордажа для пиратов:\n0 -10 = 5%25\n-10 -100 = 15%25\n-100 -1000 = 30%25\n-1000 -10000 = 40%25\nменьше -10000 = 50%25\n\n<b>Общая тактика:</b>\nНападать двумя малыми флотами хуже, чем одним большим.\nНападать поочередно хуже, чем нападать с малой разницей во времени (относится к ситуации, когда нельзя объединить корабли в общий флот)');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(58, '<b>Конспект по планетоведению</b>\n\n<font color="#FFFFFF"><b>Персонаж</b></font>\nМодуль управления персонажем. Слева отображается основная информация о вас.\n\n<font color="#00FFFF">Родная звезда, родная планета</font> - место вашей высадки, именно на этой планете находится ваша капсула и в случае вашей гибели вас воскресят на этой планете.\n\n<font color="#00FFFF">Звезда, планета</font> - ваше настоящее местонахождение. Если вы находитесь в полете или в области гиперпространства информация может не отображаться.\n\n<font color="#00FFFF">Кредитов</font> - ваш счет в банке. Это ваши свободные средства, которые вы можете использовать для покупки товара.\n\n<font color="#00FFFF">Конфедератов</font> - ваш счет в валюте конфедерации. Эти средства вы можете использовать при расчете с конфедерацией. Для пополнения счета нужно воспользоваться ссылкой "Купить" расположенной справа.\n\n<font color="#00FFFF">Роботов</font> - количество автономных роботов. Роботы не относятся к физическим объектам, поэтому их общее количество можно посмотреть только тут.\n\n<font color="#00FFFF">Уровень военного обучения</font> - статус и уровень вашего военного мастерства, данный показатель будет увеличиваться или уменьшаться на протяжении игры в зависимости от успешности ваших боевых действий. Чем больше побед вы одержите в бою, тем выше будет уровень.\n\n<font color="#00FFFF">Уровень ответственности</font> - основной показатель отношений между вами и конфедерацией. При положительном уровне вы являетесь добропорядочным гражданином, и всяческая агрессия против вас будет рассматриваться как угроза конфедерации. При отрицательном уровне вы являетесь пиратом, и агрессия против вас поощряется.\n\n<font color="#00FFFF">Приобретенный опыт</font> - показатель ваших действий в игре. Увеличивается от любого действия, начиная от постройки или переработки, и заканчивая разработкой сложных макетов и чертежей. Любое ваше действие в той или иной степени увеличивает количество опыта.\n\n<font color="#FFFFFF"><b>Местность</b></font>\nМодуль отображения внешней среды. Всегда показывает то место, где находится персонаж. Разделяется на 3 основных типа: планету, орбиту, станцию. Во время перемещений (перелетов) отображается ход перемещения и оставшееся время до окончания перелета.\n\n<font color="#00FFFF">Планета</font> - отображается, если вы находитесь на планете, непосредственно или в корабле, в модуле отображается поверхность планеты и панель управления. Панель управления имеет 3 кладки: информация, использовать, улучшить. Через панель управления осуществляются все действия на планете. Рядом с панелью управления (в левом верхнем углу) расположена карта местности, при помощи которой можно быстро переместиться в любую точку на поверхности. На карте отображается примерное расположение различных пород, ваши постройки, а так же их занятость. По цвету можно легко определить простаивающие производства - они обозначаются белым цветом. Если в энциклопедии выбрать пункт "Показать на карте" именно на этой мини-карте будут стоять отметки о найденных ископаемых, черным цветом - залежи глубинного слоя, темно синим - залежи среднего слоя.\n\n<font color="#00FFFF">Орбита</font> - отображается, если вы в корабле находитесь на орбите планеты. Орбита представляет собой линию из "точек стояния". В каждой точке может располагаться постройка. На орбите строятся орбитальные спутники, склады и производства. В отличии от планетарных заводов на орбите имеется только одно строение которое работает и с чертежами и с макетами, оно более универсально. У орбитальных построек нет аналога нанодиспенсера. На родной планете основной орбитальной постройкой является торговая станция. В основном орбитальные постройки используются как первая линия обороны на ничьих планетах. Не смотря на слабый уровень защиты орбитальных сооружений, они дают время среагировать на внешнюю атаку. Самым используемым орбитальным спутником является "Геологический спутник" - он позволяет открыть все залежи планеты при усовершенствовании. Строить на орбите можно не выгружая ресурсы из кораблей, достаточно, что бы корабль с ресурсами для постройки находился на орбите в начале строительства.\n\n<font color="#00FFFF">Станция</font> - отображается, если вы находитесь на станции, непосредственно или в корабле. Первичное назначение станции это защита планеты от всех возможных посягательств. Именно благодаря торговой станции никто не имеет возможности использовать оружие на орбите родной планеты. Так же блокируется всякая попытка приземлиться на планету. Станция так же может использоваться как склад для перемещения товара. Если станция находится на родной планете, вы можете перемещать товар на станцию и обратно на корабль. Если вы приземлились на чужой станции, то вам доступно только перемещение товара между вашими кораблями, то есть любую станцию в галактике можно использовать для дозаправки ваших кораблей.\nНаходясь в станции, вам предоставляется интерфейс для торговли. Торговля представляет собой аналог биржевых сделок.\n\n<font color="#00FF00">Покупка</font> - при покупке на вашем счете блокируется полная сумма закупки, если вы отменяете сделку, сумма полностью возвращается. При закупке необходимо учитывать рыночную стоимость, которая указывается на графике. Если график пуст - значит вы единственный покупатель. Чем выше цена закупки, тем больше вероятность, что вам продадут товар. Товар с самой высокой ценой закупки отображается в торговом компьютере как самая выгодная сделка. Запрос на закупку не может превышать свободную сумму на вашем счету. Купить можно только тот товар, который присутствует физически в галактике. Если нигде в галактике нет законсервированного Уничтожителя - вы не сможете его купить.\n\n<font color="#00FF00">Продажа</font> - при продаже товар переносится на склад продажи и блокируется там до самой продажи или до отмены сделки. Товар, находящийся на складе продажи не занимает места на складе станции. Чем ниже цена продажи товара, тем больше вероятность, что его купят. При определении цены следует учитывать среднюю цену, выставленную в галактике, она отображается на графике. Если график пуст - вы единственный продавец.\n\nСделку необходимо сохранить, чтобы она стала доступна для всех.\n\nСправа отображаются все сделки выставленные вами на станции. Для быстрой коррекции сделки достаточно выбрать ее из списка, изменить значения и сохранить. Цвет сделки обозначает направление. Красные - закупка, зеленые - продажа, желтые - двунаправленные.\n\n<font color="#FFFFFF"><b>Корабли</b></font>\nМодуль дает возможность управлять всеми кораблями, а так же просматривать чужие корабли, находящиеся с вашими кораблями в одном месте. Корабли могут быть объединены во флот, при этом в списке будет отображаться только название флота. Флот имеет большое преимущество при расходе топлива, достаточно одного заправленного корабля и все корабли флота будут пользоваться его содержимым, такой корабль условно называется заправщиком. Флот не ограничен по количеству и составу кораблей, однако скорость флота равна скорости самого медленного корабля, а возможности перемещения флота равны возможностям каждого корабля, если в составе флота есть хотя бы один корабль без антигравитационного двигателя - флот не сможет приземлиться на планету.\nЭкран условно разделен на две части - панель управления и основной экран. В свою очередь панель управления состоит из панели кораблей и приказов.\n\n<font color="#00FFFF">Панель кораблей</font> - сверху выводится список кораблей. Сначала отображаются ваши корабли в зависимости от их положения.\nПринцип сортировки следующий:\n1.перемещающиеся корабли\n2.корабли в открытом космосе\n3.корабли на орбите планеты\n4.корабли на поверхности планеты\n5.корабли пристыкованные к орбитальным постройкам\nЗатем идут законсервированные корабли единым списком. И под конец идут чужие корабли, находящиеся с вами в одной точке.\nКорабли можно выделять сразу группой (используйте кнопки Ctrl или Shift) это позволит объединять корабли во флот.\n\n<font color="#00FFFF">Приказы</font> - количество приказов зависит от возможностей корабля, его местоположения и окружающего пространства. Для группы кораблей доступно только 2 приказа, это или объединение во флот или приказ к атаке. Практически каждый приказ влияет на отображение главного экрана.\n\n<font color="#00FFFF">Переместится в системе</font> - при этом приказе на главный экран выводится карта звездной системы. Для перемещения достаточно выбрать точку, в которую следует отправить корабль. Желтыми окружностями отображаются чужие корабли, зелеными свои. Внизу пишется, сколько всего объектов было найдено во время сканирования системы. Чужие корабли выводятся только в том случае, если в системе есть хотя бы один корабль оснащенный радаром. Белая линия курса говорит о полете к планете, зеленая о полете в свободную точку космоса, красная о нехватки топлива для полета. В верхней части написано название и координаты звезды. Во время выбора точки перемещения внизу выводится название или координаты места назначения, примерное время полета, а так же количество топлива. Если строка с топливом окрашена желтым, значит топлива хватит только в один конец.\n\n<font color="#00FFFF">Переместится в галактике</font> - при этом приказе выводится карта звездного неба, на карте отмечаются только ваши корабли, поскольку нет возможности сканировать такие огромные расстояния. Кратность синей сетки на заднем плане 100. В центральной части галактике скопление звезд более плотное. Звезда, отмеченная зеленой окружностью это ваша родная звезда. Белой окружностью отмечается звезда, если вы взяли какое-то задание на выполнение.\n\n<font color="#FFFFFF"><b>Склад</b></font>\nМодуль дает возможность переместить любой груз, который находится в вашем распоряжении. Верхняя часть управления относится к кораблю - основной единице склада. Нижняя часть определяет второй склад для передачи, которым может быть поверхность планеты, орбита планеты или другой корабль. Для перемещения товара необходимо выбрать два смежных склада, выбрать товар переместить его. После выбора товара можно определить количество в центральной части управления или "переместить все" - в этом случае будет перемещено максимально возможное количество товара. Товар можно выбирать группой, для этого надо использовать клавиши Ctrl или Shift, в этом случае товар будет передаваться в порядке выбора до тех пор, пока будет такая возможность. Если выбрать группу товара и отдать команду "переместить все" - будет перемещено максимально возможное количество товара. Если определить количество вручную, каждая единица товара будет перемещена в том количестве, которое определено, или меньше при нехватке места или товара.\nПереместить товар из корабля в корабль можно на любой торговой станции (даже чужой) этим можно воспользоваться для дозаправки своих кораблей. Товар, находящийся на орбитальном складе или на поверхности планеты не имеет принадлежности и его может взять любой, кто окажется в этом месте. Исключение составляет только торговая станция.\n\n<font color="#FFFFFF"><b>Торговля</b></font>\nМодуль отображает все сделки, а так же позволяет осуществлять любые торговые операции.\n	<font color="#00FFFF">Торговый компьютер</font> - отображает все сделки в галактике, сделка считается выгодной если цена продажи ниже цены покупки (без расчета затрат на доставку), в данном случае сделка отображается зеленым цветом. Если сделка не парная (есть только продавец или только покупатель) такая сделка отображается серым цветом. Данный раздел очень полезен торговцам, именно через торговый компьютер можно быстро и удобно найти выгодный товар. Для торгового флота главная добыча сводится к водороду и урану, чтобы обеспечить себя бесплатным топливом.\n	<font color="#00FFFF">Покупка</font> - В разделе отображаются только те корабли, которые находятся на чужих торговых станциях. Если на станции есть продаваемый товар, то вы можете его купить, используя любой из ваших кораблей. Товар нельзя купить удаленно, а потом забрать, для торговли необходимо присутствие вашего корабля на станции. Покупать можно любое количество товара.\n	<font color="#00FFFF">Продажа</font> - Так же, как и в разделе покупки, отображаются только корабли на чужих торговых станциях. Если у вас на корабле есть товар, который требуется станции, он отобразится, и вы сможете его продать. Сумма сделки зависит от количества товара и цены за него. Продавать можно любое количество товара.\n	<font color="#00FFFF">Конфедерация</font> - Раздел позволяющий покупать напрямую у Конфедерации планет. Некоторые товары можно приобрести только у конфедерации, например, Автономные роботы. Товар, купленный у конфедерации, моментально доставят на вашу торговую станцию. Конфедерация не занимается покупкой товара. Как правило, цены конфедерации выше, чем средняя цена по галактике, однако моментальная доставка товара на вашу торговую станцию может оказаться выгоднее, чем денежная экономия. Для покупки необходимо выбрать товар и осуществить покупку. Некоторые товары можно приобрести как за кредиты, так и за конфедераты, это позволяет выбрать наиболее выгодные условия.\n\n<font color="#FFFFFF"><b>Прочее</b></font>\nМодуль объединяет в себе несколько информационных разделов.\n	<font color="#00FFFF">Энциклопедия</font> - Главный источник знаний. Любой товар, имеющийся в галактике, имеет свое описание. Прежде чем строить или покупать корабль можно посмотреть полный перечень его характеристик, а так же набор деталей требующихся для производства. У большинства деталей есть подробное описание позволяющее понять суть их работы.\n	<font color="#00FFFF">Роботы</font> - Все автономные роботы, которые имеются в вашем распоряжении, присутствуют в этом разделе. Красным цветом отображается робот, который занят на производстве, зеленым - свободный робот. Если робот не занят производством, время его использования не тратится. После того, как робот закончился, он исчезает из списка. В списке всегда можно посмотреть, где и на каком производстве задействованы ваши роботы.\n	<font color="#00FFFF">Настройки</font> - Раздел позволяет настроить все отчеты, определив, что необходимо срочно сообщить в чат, а что можно отослать в виде сообщения. Так же тут можно настроить громкость спецэффектов и музыки.\n\n<font color="#FFFFFF"><b>Чат</b></font>\nЧат состоит из 3-х основных частей:\n	<font color="#00FFFF">чтение</font> - основной экран чата - куда выводятся все сообщения от системы и других игроков.\nСистемное сообщение - время отображается зеленым цветом, сообщение серым\nОбычное сообщение - время отображается голубым цветом, сообщение белым (ник игрока желтым)\nПриватное сообщение - время отображается красным, сообщение белым (ник игрока желтым)\n	<font color="#00FFFF">написание</font> - строка внизу экрана предназначена для отправки сообщения в чат. Если кликнуть мышкой в ник игрока, то его ник автоматически пропишется в строке для ответа. Если игрок написал вам приватное сообщение, то и ответ будет приватный. Для начала приватного сообщения необходимо кликнуть в замочек слева от имени игрока в списке.\n	<font color="#00FFFF">список игроков</font> - список отображается в алфавитном порядке. Цвет имени говорит о статусе в обществе. Белый цвет - обозначает нейтральный статус. Зеленый - говорит о добропорядочности игрока (за нападение на такого пилота игрока наказывают). Красный цвет - говорит о принадлежности к пиратам, справа в скобках отображается награда за "голову" пирата. Награда выплачивается только в случае, если игрок лично присутствовал в уничтоженном корабле. Во всех остальных случаях выплачивается часть стоимости корабля или постройки.\n'),
(1000, '<b>Серебро</b> <u><a href=''page.php?id=2%26ml=1000''>Показать на карте</a></u>\nПолезное ископаемое.\n\nСодержится в минералах:\n<u><a href=''page.php?id=6%26itm=Аргентит''>Аргентит</a></u>				87\n<u><a href=''page.php?id=6%26itm=Пираргирит''>Пираргирит</a></u>			60\n<u><a href=''page.php?id=6%26itm=Сильванит''>Сильванит</a></u>				6\n<u><a href=''page.php?id=6%26itm=Алабандин''>Алабандин</a></u>			1'),
