-- tituls for premium title objects present in catalog
SELECT o.id, o.id, o.name
FROM objects o
WHERE o.class = 9 AND o.cprice > 0
ON DUPLICATE KEY UPDATE object_id = VALUES(object_id), name = VALUES(name);

-- market rows for tradeable resource objects (class 1)
SELECT o.id, 0, 0, o.myprice, 0, 0, 100
FROM objects o
WHERE o.class = 1
ON DUPLICATE KEY UPDATE avg_price = VALUES(avg_price);

UPDATE ship_types SET w_sum = w_power * IF(w_count = 0, 1, w_count);
UPDATE objects SET minprice = 0 WHERE minprice IS NULL;
